1	/**
2	 * Pure canvas renderer for the arrangement view.
3	 * No DOM access -- only draws to the CanvasRenderingContext2D passed in.
4	 */
5	import { isAudioClip } from "@state/track/types";
6	import type { TrackModel, ClipModel } from "@state/track/types";
7	import type { AutomationLane } from "@audio/automation/automation-types";
8	import { evaluateCurve } from "@audio/automation/automation-curve";
9	import { RULER_HEIGHT, CLIP_PADDING } from "./constants";
10	
11	// -- Design token constants (canvas cannot read CSS vars) ---------------------
12	
13	const COLOR = {
14	  black: "#000000",
15	  white: "#ffffff",
16	  red: "#ff0000",
17	  pink: "#ff2d6f",
18	  gray900: "#111111",
19	  gray700: "#333333",
20	  gray500: "#666666",
21	} as const;
22	
23	const FONT_MONO = "'JetBrains Mono', monospace" as const;
24	const TEXT_XS = 10;
25	const TEXT_SM = 12;
26	const BORDER_WIDTH = 2;
27	const COLOR_STRIP_WIDTH = 4;
28	
29	// -- Public types -------------------------------------------------------------
30	
31	export type ArrangementViewState = {
32	  scrollX: number;
33	  scrollY: number;
34	  pixelsPerSecond: number;
35	  trackHeight: number;
36	  headerWidth: number;
37	};
38	
39	export type RenderContext = {
40	  ctx: CanvasRenderingContext2D;
41	  width: number;
42	  height: number;
43	  view: ArrangementViewState;
44	  tracks: readonly TrackModel[];
45	  clips: Record<string, ClipModel>;
46	  selectedClipIds: readonly string[];
47	  cursorSeconds: number;
48	  bpm: number;
49	  automationLanes?: Record<string, readonly AutomationLane[]>;
50	  clipPeaks?: Record<string, { peaks: Float32Array; length: number }>;
51	};
52	
53	// -- Helpers ------------------------------------------------------------------
54	
55	function secondsToX(seconds: number, view: ArrangementViewState): number {
56	  return view.headerWidth + (seconds - view.scrollX) * view.pixelsPerSecond;
57	}
58	
59	function trackY(index: number, view: ArrangementViewState): number {
60	  return RULER_HEIGHT + index * view.trackHeight - view.scrollY;
61	}
62	
63	/** Convert a hex color (#rrggbb) to rgba with given alpha (0-1). */
64	function hexToRgba(hex: string, alpha: number): string {
65	  if (!/^#[0-9a-fA-F]{6}$/.test(hex)) {
66	    return `rgba(128,128,128,${String(alpha)})`;
67	  }
68	  const r = parseInt(hex.slice(1, 3), 16);
69	  const g = parseInt(hex.slice(3, 5), 16);
70	  const b = parseInt(hex.slice(5, 7), 16);
71	  return `rgba(${String(r)},${String(g)},${String(b)},${String(alpha)})`;
72	}
73	
74	// -- Rendering stages ---------------------------------------------------------
75	
76	function drawBackground(rc: RenderContext): void {
77	  const { ctx, width, height } = rc;
78	  ctx.fillStyle = COLOR.gray900;
79	  ctx.fillRect(0, 0, width, height);
80	}
81	
82	function drawTimeRuler(rc: RenderContext): void {
83	  const { ctx, width, view, bpm } = rc;
84	  const secPerBeat = 60 / bpm;
85	  const secPerBar = secPerBeat * 4;
86	
87	  // Ruler background
88	  ctx.fillStyle = COLOR.black;
89	  ctx.fillRect(0, 0, width, RULER_HEIGHT);
90	
91	  // Bar labels
92	  ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
93	  ctx.fillStyle = COLOR.gray500;
94	  ctx.textBaseline = "middle";
95	  ctx.textAlign = "center";
96	
97	  const startBar = Math.max(0, Math.floor(view.scrollX / secPerBar));
98	  const endSec =
99	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
100	  const endBar = Math.ceil(endSec / secPerBar) + 1;
101	
102	  for (let bar = startBar; bar < endBar; bar++) {
103	    const x = secondsToX(bar * secPerBar, view);
104	    if (x >= view.headerWidth && x <= width) {
105	      ctx.fillText(String(bar + 1), x, RULER_HEIGHT / 2);
106	    }
107	  }
108	}
109	
110	function drawGrid(rc: RenderContext): void {
111	  const { ctx, width, height, view, bpm } = rc;
112	  const secPerBeat = 60 / bpm;
113	  const secPerBar = secPerBeat * 4;
114	
115	  // Determine visible range in seconds
116	  const startSec = view.scrollX;
117	  const endSec =
118	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
119	
120	  // Determine grid step -- skip beats when zoomed out too far
121	  const minPxPerLine = 12;
122	  let step = secPerBeat;
123	  while (step * view.pixelsPerSecond < minPxPerLine) {
124	    step *= 2;
125	  }
126	
127	  const firstBeat = Math.floor(startSec / step) * step;
128	
129	  ctx.save();
130	  for (let t = firstBeat; t <= endSec; t += step) {
131	    const x = secondsToX(t, view);
132	    if (x < view.headerWidth || x > width) continue;
133	
134	    // Check if this line sits on a bar boundary (use integer arithmetic to avoid float drift)
135	    const nearestBar = Math.round(t / secPerBar) * secPerBar;
136	    const isBar = Math.abs(t - nearestBar) < 0.001;
137	    ctx.strokeStyle = COLOR.gray700;
138	    ctx.lineWidth = isBar ? 2 : 1;
139	
140	    ctx.beginPath();
141	    ctx.moveTo(x, RULER_HEIGHT);
142	    ctx.lineTo(x, height);
143	    ctx.stroke();
144	  }
145	  ctx.restore();
146	}
147	
148	function drawTrackLanes(rc: RenderContext): void {
149	  const { ctx, width, view, tracks } = rc;
150	
151	  for (let i = 0; i < tracks.length; i++) {
152	    const y = trackY(i, view);
153	    const bottom = y + view.trackHeight;
154	
155	    if (bottom < RULER_HEIGHT || y > rc.height) continue;
156	
157	    // Lane separator
158	    ctx.strokeStyle = COLOR.gray700;
159	    ctx.lineWidth = BORDER_WIDTH;
160	    ctx.beginPath();
161	    ctx.moveTo(0, bottom);
162	    ctx.lineTo(width, bottom);
163	    ctx.stroke();
164	  }
165	}
166	
167	function drawTrackHeaders(rc: RenderContext): void {
168	  const { ctx, view, tracks } = rc;
169	
170	  for (let i = 0; i < tracks.length; i++) {
171	    const track = tracks[i];
172	    if (track === undefined) continue;
173	    const y = trackY(i, view);
174	
175	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
176	
177	    // Header background
178	    ctx.fillStyle = COLOR.black;
179	    ctx.fillRect(0, y, view.headerWidth, view.trackHeight);
180	
181	    // Color strip (4px vertical bar)
182	    ctx.fillStyle = track.color;
183	    ctx.fillRect(0, y, COLOR_STRIP_WIDTH, view.trackHeight);
184	
185	    // Track name
186	    ctx.font = `${String(TEXT_SM)}px ${FONT_MONO}`;
187	    ctx.fillStyle = COLOR.white;
188	    ctx.textBaseline = "middle";
189	    ctx.textAlign = "left";
190	    ctx.fillText(track.name, COLOR_STRIP_WIDTH + 8, y + view.trackHeight / 2);
191	
192	    // Armed indicator (hot pink per R-STA-02)
193	    if (track.armed) {
194	      ctx.fillStyle = COLOR.pink;
195	      ctx.fillRect(0, y, COLOR_STRIP_WIDTH, view.trackHeight);
196	    }
197	
198	    // Mute/Solo indicators
199	    const indicatorY = y + view.trackHeight / 2;
200	    ctx.font = `bold ${String(TEXT_XS)}px ${FONT_MONO}`;
201	    ctx.textAlign = "center";
202	
203	    if (track.armed) {
204	      ctx.fillStyle = COLOR.pink;
205	      ctx.fillText("R", view.headerWidth - 54, indicatorY);
206	    }
207	    if (track.muted) {
208	      ctx.fillStyle = COLOR.gray500;
209	      ctx.fillText("M", view.headerWidth - 36, indicatorY);
210	    }
211	    if (track.solo) {
212	      ctx.fillStyle = COLOR.gray500;
213	      ctx.fillText("S", view.headerWidth - 18, indicatorY);
214	    }
215	
216	    // Header right border
217	    ctx.strokeStyle = COLOR.gray700;
218	    ctx.lineWidth = BORDER_WIDTH;
219	    ctx.beginPath();
220	    ctx.moveTo(view.headerWidth, y);
221	    ctx.lineTo(view.headerWidth, y + view.trackHeight);
222	    ctx.stroke();
223	  }
224	}
225	
226	function drawClips(rc: RenderContext): void {
227	  const { ctx, view, tracks, clips, selectedClipIds } = rc;
228	  const selectedSet = new Set(selectedClipIds);
229	
230	  for (let i = 0; i < tracks.length; i++) {
231	    const track = tracks[i];
232	    if (track === undefined) continue;
233	    const y = trackY(i, view);
234	
235	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
236	
237	    for (const clipId of track.clipIds) {
238	      const clip = clips[clipId];
239	      if (clip === undefined) continue;
240	
241	      const x = secondsToX(clip.startTime, view);
242	      const w = clip.duration * view.pixelsPerSecond;
243	
244	      // Skip clips that are fully out of view
245	      if (x + w < view.headerWidth || x > rc.width) continue;
246	
247	      const clipY = y + CLIP_PADDING;
248	      const clipH = view.trackHeight - CLIP_PADDING * 2;
249	
250	      // Clip fill (track color at 60% opacity)
251	      ctx.fillStyle = hexToRgba(track.color, 0.6);
252	      ctx.fillRect(x, clipY, w, clipH);
253	
254	      // Waveform peaks (audio clips only)
255	      if (isAudioClip(clip)) {
256	        const peakData = rc.clipPeaks?.[clip.id];
257	        if (peakData && peakData.length > 0) {
258	          ctx.save();
259	          ctx.beginPath();
260	          ctx.rect(x, clipY, w, clipH);
261	          ctx.clip();
262	
263	          ctx.fillStyle = "rgba(255,255,255,0.4)";
264	          const mid = clipY + clipH / 2;
265	          const halfH = clipH / 2;
266	          const barWidth = Math.max(1, w / peakData.length);
267	
268	          for (let p = 0; p < peakData.length; p++) {
269	            const min = peakData.peaks[p * 2];
270	            const max = peakData.peaks[p * 2 + 1];
271	            if (min === undefined || max === undefined) continue;
272	            const px = x + (p / peakData.length) * w;
273	            const top = mid - max * halfH;
274	            const bottom = mid - min * halfH;
275	            ctx.fillRect(px, top, barWidth, bottom - top);
276	          }
277	
278	          ctx.restore();
279	        }
280	      }
281	
282	      // Clip border
283	      const isSelected = selectedSet.has(clip.id);
284	      ctx.strokeStyle = isSelected ? COLOR.white : track.color;
285	      ctx.lineWidth = BORDER_WIDTH;
286	      ctx.strokeRect(x, clipY, w, clipH);
287	
288	      // Clip name label
289	      ctx.save();
290	      ctx.beginPath();
291	      ctx.rect(x, clipY, w, clipH);
292	      ctx.clip();
293	      ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
294	      ctx.fillStyle = COLOR.white;
295	      ctx.textBaseline = "top";
296	      ctx.textAlign = "left";
297	      ctx.fillText(clip.name, x + 4, clipY + 4);
298	      ctx.restore();
299	    }
300	  }
301	}
302	
303	const AUTOMATION_LINE_COLOR = "#00ccff";
304	const AUTOMATION_POINT_RADIUS = 3;
305	const AUTOMATION_SAMPLES_PER_PX = 4; // evaluate every 4 pixels for smooth curves
306	
307	function drawAutomationLanes(rc: RenderContext): void {
308	  const { ctx, view, tracks, automationLanes } = rc;
309	  if (!automationLanes) return;
310	
311	  for (let i = 0; i < tracks.length; i++) {
312	    const track = tracks[i];
313	    if (track === undefined) continue;
314	    const lanes = automationLanes[track.id];
315	    if (!lanes || lanes.length === 0) continue;
316	
317	    const y = trackY(i, view);
318	    const laneBottom = y + view.trackHeight;
319	    if (laneBottom < RULER_HEIGHT || y > rc.height) continue;
320	
321	    for (const lane of lanes) {
322	      if (lane.points.length === 0) continue;
323	
324	      ctx.save();
325	
326	      // Clip to track lane area (past the header)
327	      ctx.beginPath();
328	      ctx.rect(
329	        view.headerWidth,
330	        y + CLIP_PADDING,
331	        rc.width - view.headerWidth,
332	        view.trackHeight - CLIP_PADDING * 2,
333	      );
334	      ctx.clip();
335	
336	      // Draw the curve as connected line segments
337	      const startSec = view.scrollX;
338	      const endSec =
339	        view.scrollX + (rc.width - view.headerWidth) / view.pixelsPerSecond;
340	      const step = AUTOMATION_SAMPLES_PER_PX / view.pixelsPerSecond;
341	      const laneH = view.trackHeight - CLIP_PADDING * 2;
342	      const laneTop = y + CLIP_PADDING;
343	
344	      ctx.strokeStyle = AUTOMATION_LINE_COLOR;
345	      ctx.lineWidth = 1.5;
346	      ctx.beginPath();
347	
348	      let first = true;
349	      for (let t = startSec; t <= endSec; t += step) {
350	        const val = evaluateCurve(lane.points, t);
351	        const px = secondsToX(t, view);
352	        const py = laneTop + laneH * (1 - val); // 1.0 at top, 0.0 at bottom
353	        if (first) {
354	          ctx.moveTo(px, py);
355	          first = false;
356	        } else {
357	          ctx.lineTo(px, py);
358	        }
359	      }
360	      ctx.stroke();
361	
362	      // Draw point handles
363	      ctx.fillStyle = AUTOMATION_LINE_COLOR;
364	      for (const pt of lane.points) {
365	        const px = secondsToX(pt.time, view);
366	        const py = laneTop + laneH * (1 - pt.value);
367	        if (px < view.headerWidth || px > rc.width) continue;
368	
369	        ctx.beginPath();
370	        ctx.arc(px, py, AUTOMATION_POINT_RADIUS, 0, Math.PI * 2);
371	        ctx.fill();
372	      }
373	
374	      ctx.restore();
375	    }
376	  }
377	}
378	
379	function drawPlayhead(rc: RenderContext): void {
380	  const { ctx, height, view, cursorSeconds } = rc;
381	  const x = secondsToX(cursorSeconds, view);
382	
383	  if (x < view.headerWidth || x > rc.width) return;
384	
385	  ctx.strokeStyle = COLOR.red;
386	  ctx.lineWidth = 2;
387	  ctx.beginPath();
388	  ctx.moveTo(x, 0);
389	  ctx.lineTo(x, height);
390	  ctx.stroke();
391	}
392	
393	// -- Public API ---------------------------------------------------------------
394	
395	export function renderArrangement(rc: RenderContext): void {
396	  drawBackground(rc);
397	  drawTimeRuler(rc);
398	  drawGrid(rc);
399	  drawTrackLanes(rc);
400	  drawTrackHeaders(rc);
401	  drawClips(rc);
402	  drawAutomationLanes(rc);
403	  drawPlayhead(rc);
404	}
