1	/**
2	 * Pointer interaction handlers for the arrangement canvas.
3	 * Manages drag operations for clip move, trim, split, and selection.
4	 * Pushes undo commands on drag completion.
5	 */
6	import { useCallback, useRef, useState } from "react";
7	import { useDawStore } from "@state/store";
8	import type { ClipModel, MidiClipModel } from "@state/track/types";
9	import { isAudioClip, isMidiClip } from "@state/track/types";
10	import type { UndoCommand } from "@state/undo";
11	import { sharedUndoManager } from "@state/undo";
12	import { AddClipCommand, SplitClipCommand } from "@state/track/track-commands";
13	import type { ArrangementViewState } from "./arrangement-renderer";
14	import { hitTest, xToSeconds, snapToGrid, type GridSnap } from "./hit-test";
15	import { RULER_HEIGHT } from "./constants";
16	
17	type DragState =
18	  | { kind: "idle" }
19	  | {
20	      kind: "move-clip";
21	      clipId: string;
22	      originTrackId: string;
23	      startX: number;
24	      startTime: number;
25	      beforeClip: ClipModel;
26	    }
27	  | {
28	      kind: "trim-left";
29	      clipId: string;
30	      startX: number;
31	      originalStart: number;
32	      originalSourceOffset: number;
33	      originalDuration: number;
34	      beforeClip: ClipModel;
35	    }
36	  | {
37	      kind: "trim-right";
38	      clipId: string;
39	      startX: number;
40	      originalEnd: number;
41	      originalStart: number;
42	      beforeClip: ClipModel;
43	    }
44	  | {
45	      kind: "rubber-band";
46	      startX: number;
47	      startY: number;
48	    };
49	
50	export type ArrangementInteractions = {
51	  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
52	  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
53	  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
54	  onDoubleClick: (e: React.MouseEvent<HTMLCanvasElement>) => void;
55	  cursor: string;
56	};
57	
58	export function useArrangementInteractions(
59	  view: ArrangementViewState,
60	  gridSnap: GridSnap,
61	  onOpenPianoRoll?: (clipId: string) => void,
62	): ArrangementInteractions {
63	  const dragRef = useRef<DragState>({ kind: "idle" });
64	  const [cursor, setCursor] = useState("default");
65	
66	  const getCanvasPos = useCallback(
67	    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
68	      const rect = e.currentTarget.getBoundingClientRect();
69	      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
70	    },
71	    [],
72	  );
73	
74	  const onPointerDown = useCallback(
75	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
76	      const { x, y } = getCanvasPos(e);
77	      const state = useDawStore.getState();
78	      const hit = hitTest(x, y, view, state.tracks, state.clips);
79	
80	      switch (hit.kind) {
81	        case "clip-body": {
82	          const clip = state.clips[hit.clipId];
83	          if (clip === undefined) break;
84	
85	          if (e.shiftKey) {
86	            const current = [...state.selectedClipIds];
87	            const idx = current.indexOf(hit.clipId);
88	            if (idx >= 0) {
89	              current.splice(idx, 1);
90	            } else {
91	              current.push(hit.clipId);
92	            }
93	            state.setSelectedClipIds(current);
94	          } else if (!state.selectedClipIds.includes(hit.clipId)) {
95	            state.setSelectedClipIds([hit.clipId]);
96	          }
97	
98	          e.currentTarget.setPointerCapture(e.pointerId);
99	          dragRef.current = {
100	            kind: "move-clip",
101	            clipId: hit.clipId,
102	            originTrackId: clip.trackId,
103	            startX: x,
104	            startTime: clip.startTime,
105	            beforeClip: { ...clip },
106	          };
107	          break;
108	        }
109	        case "clip-left-edge": {
110	          const clip = state.clips[hit.clipId];
111	          if (clip === undefined) break;
112	          state.setSelectedClipIds([hit.clipId]);
113	          e.currentTarget.setPointerCapture(e.pointerId);
114	          dragRef.current = {
115	            kind: "trim-left",
116	            clipId: hit.clipId,
117	            startX: x,
118	            originalStart: clip.startTime,
119	            originalSourceOffset: isAudioClip(clip) ? clip.sourceOffset : 0,
120	            originalDuration: clip.duration,
121	            beforeClip: { ...clip },
122	          };
123	          break;
124	        }
125	        case "clip-right-edge": {
126	          const clip = state.clips[hit.clipId];
127	          if (clip === undefined) break;
128	          state.setSelectedClipIds([hit.clipId]);
129	          e.currentTarget.setPointerCapture(e.pointerId);
130	          dragRef.current = {
131	            kind: "trim-right",
132	            clipId: hit.clipId,
133	            startX: x,
134	            originalEnd: clip.startTime + clip.duration,
135	            originalStart: clip.startTime,
136	            beforeClip: { ...clip },
137	          };
138	          break;
139	        }
140	        case "ruler": {
141	          state.setCursor(Math.max(0, hit.timeSeconds));
142	          break;
143	        }
144	        case "empty-lane": {
145	          if (!e.shiftKey) {
146	            state.setSelectedClipIds([]);
147	          }
148	          e.currentTarget.setPointerCapture(e.pointerId);
149	          dragRef.current = { kind: "rubber-band", startX: x, startY: y };
150	          break;
151	        }
152	        case "track-header": {
153	          if (e.shiftKey) {
154	            const current = [...state.selectedTrackIds];
155	            const idx = current.indexOf(hit.trackId);
156	            if (idx >= 0) {
157	              current.splice(idx, 1);
158	            } else {
159	              current.push(hit.trackId);
160	            }
161	            state.setSelectedTrackIds(current);
162	          } else {
163	            state.setSelectedTrackIds([hit.trackId]);
164	          }
165	          break;
166	        }
167	        case "none":
168	          break;
169	      }
170	    },
171	    [view, getCanvasPos],
172	  );
173	
174	  const onPointerMove = useCallback(
175	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
176	      const { x, y } = getCanvasPos(e);
177	      const drag = dragRef.current;
178	      const state = useDawStore.getState();
179	
180	      if (drag.kind === "idle") {
181	        const hit = hitTest(x, y, view, state.tracks, state.clips);
182	        switch (hit.kind) {
183	          case "clip-left-edge":
184	          case "clip-right-edge":
185	            setCursor("ew-resize");
186	            break;
187	          case "clip-body":
188	            setCursor("grab");
189	            break;
190	          default:
191	            setCursor("default");
192	            break;
193	        }
194	        return;
195	      }
196	
197	      switch (drag.kind) {
198	        case "move-clip": {
199	          setCursor("grabbing");
200	          const deltaPx = x - drag.startX;
201	          const deltaSec = deltaPx / view.pixelsPerSecond;
202	          const newTime = snapToGrid(
203	            Math.max(0, drag.startTime + deltaSec),
204	            state.bpm,
205	            gridSnap,
206	          );
207	
208	          const trackIndex = Math.floor(
209	            (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
210	          );
211	          const targetTrack = state.tracks[trackIndex];
212	          const targetTrackId =
213	            targetTrack !== undefined ? targetTrack.id : drag.originTrackId;
214	
215	          state.moveClip(drag.clipId, newTime, targetTrackId);
216	          break;
217	        }
218	        case "trim-left": {
219	          setCursor("ew-resize");
220	          const deltaPx = x - drag.startX;
221	          const deltaSec = deltaPx / view.pixelsPerSecond;
222	          const newStart = snapToGrid(
223	            Math.max(0, drag.originalStart + deltaSec),
224	            state.bpm,
225	            gridSnap,
226	          );
227	          const maxStart = drag.originalStart + drag.originalDuration - 0.01;
228	          const clampedStart = Math.min(newStart, maxStart);
229	          state.trimClip(drag.clipId, clampedStart, undefined);
230	          break;
231	        }
232	        case "trim-right": {
233	          setCursor("ew-resize");
234	          const deltaPx = x - drag.startX;
235	          const deltaSec = deltaPx / view.pixelsPerSecond;
236	          const rawEnd = snapToGrid(
237	            Math.max(0.01, drag.originalEnd + deltaSec),
238	            state.bpm,
239	            gridSnap,
240	          );
241	          // Clamp so the end never crosses the clip's start
242	          const newEnd = Math.max(drag.originalStart + 0.01, rawEnd);
243	          state.trimClip(drag.clipId, undefined, newEnd);
244	          break;
245	        }
246	        case "rubber-band": {
247	          const left = Math.min(drag.startX, x);
248	          const right = Math.max(drag.startX, x);
249	          const top = Math.min(drag.startY, y);
250	          const bottom = Math.max(drag.startY, y);
251	
252	          const selected: string[] = [];
253	          for (let ti = 0; ti < state.tracks.length; ti++) {
254	            const track = state.tracks[ti];
255	            if (track === undefined) continue;
256	            const trackTop =
257	              RULER_HEIGHT + ti * view.trackHeight - view.scrollY;
258	            const trackBottom = trackTop + view.trackHeight;
259	            if (trackBottom < top || trackTop > bottom) continue;
260	
261	            for (const clipId of track.clipIds) {
262	              const clip = state.clips[clipId];
263	              if (clip === undefined) continue;
264	              const clipLeft =
265	                view.headerWidth +
266	                (clip.startTime - view.scrollX) * view.pixelsPerSecond;
267	              const clipRight = clipLeft + clip.duration * view.pixelsPerSecond;
268	              if (clipRight >= left && clipLeft <= right) {
269	                selected.push(clip.id);
270	              }
271	            }
272	          }
273	          state.setSelectedClipIds(selected);
274	          break;
275	        }
276	      }
277	    },
278	    [view, gridSnap, getCanvasPos],
279	  );
280	
281	  const onPointerUp = useCallback(
282	    (e: React.PointerEvent<HTMLCanvasElement>): void => {
283	      const drag = dragRef.current;
284	
285	      // Push undo commands for clip-mutating drags
286	      if (
287	        drag.kind === "move-clip" ||
288	        drag.kind === "trim-left" ||
289	        drag.kind === "trim-right"
290	      ) {
291	        const afterClip = useDawStore.getState().clips[drag.clipId];
292	        const before = drag.beforeClip;
293	
294	        if (
295	          afterClip !== undefined &&
296	          (before.startTime !== afterClip.startTime ||
297	            before.trackId !== afterClip.trackId ||
298	            before.duration !== afterClip.duration ||
299	            (isAudioClip(before) &&
300	              isAudioClip(afterClip) &&
301	              before.sourceOffset !== afterClip.sourceOffset))
302	        ) {
303	          const clipId = drag.clipId;
304	          const cmd: UndoCommand =
305	            drag.kind === "move-clip"
306	              ? {
307	                  type: "move-clip-drag",
308	                  execute() {
309	                    useDawStore
310	                      .getState()
311	                      .moveClip(clipId, afterClip.startTime, afterClip.trackId);
312	                  },
313	                  undo() {
314	                    useDawStore
315	                      .getState()
316	                      .moveClip(clipId, before.startTime, before.trackId);
317	                  },
318	                  serialize() {
319	                    return { clipId, before, after: afterClip };
320	                  },
321	                }
322	              : {
323	                  type: "trim-clip-drag",
324	                  execute() {
325	                    useDawStore.setState((s) => ({
326	                      clips: { ...s.clips, [clipId]: afterClip },
327	                    }));
328	                  },
329	                  undo() {
330	                    useDawStore.setState((s) => ({
331	                      clips: { ...s.clips, [clipId]: before },
332	                    }));
333	                  },
334	                  serialize() {
335	                    return { clipId, before, after: afterClip };
336	                  },
337	                };
338	          sharedUndoManager.push(cmd);
339	        }
340	      }
341	
342	      if (drag.kind !== "idle") {
343	        e.currentTarget.releasePointerCapture(e.pointerId);
344	      }
345	      dragRef.current = { kind: "idle" };
346	      setCursor("default");
347	    },
348	    [],
349	  );
350	
351	  const onDoubleClick = useCallback(
352	    (e: React.MouseEvent<HTMLCanvasElement>): void => {
353	      const { x, y } = getCanvasPos(e);
354	      const state = useDawStore.getState();
355	      const hit = hitTest(x, y, view, state.tracks, state.clips);
356	
357	      if (hit.kind === "clip-body") {
358	        const clip = state.clips[hit.clipId];
359	        if (clip !== undefined && isMidiClip(clip)) {
360	          onOpenPianoRoll?.(hit.clipId);
361	          return;
362	        }
363	        const timeSec = xToSeconds(x, view);
364	        const cmd = new SplitClipCommand(hit.clipId, timeSec);
365	        cmd.execute();
366	        sharedUndoManager.push(cmd);
367	        return;
368	      }
369	
370	      // Double-click on empty lane of instrument/drum track creates a MIDI clip
371	      if (hit.kind === "empty-lane") {
372	        const track = state.tracks.find((t) => t.id === hit.trackId);
373	        if (
374	          track !== undefined &&
375	          (track.type === "instrument" || track.type === "drum")
376	        ) {
377	          const timeSec = snapToGrid(
378	            Math.max(0, xToSeconds(x, view)),
379	            state.bpm,
380	            gridSnap,
381	          );
382	          const barsInSeconds = (60 / state.bpm) * 4; // 1 bar = 4 beats
383	          const clip: MidiClipModel = {
384	            type: "midi",
385	            id: "clip-" + crypto.randomUUID(),
386	            trackId: track.id,
387	            startTime: timeSec,
388	            duration: barsInSeconds,
389	            noteEvents: [],
390	            name: "MIDI Clip",
391	          };
392	          const cmd = new AddClipCommand(clip);
393	          cmd.execute();
394	          sharedUndoManager.push(cmd);
395	        }
396	      }
397	    },
398	    [view, gridSnap, getCanvasPos, onOpenPianoRoll],
399	  );
400	
401	  return {
402	    onPointerDown,
403	    onPointerMove,
404	    onPointerUp,
405	    onDoubleClick,
406	    cursor,
407	  };
408	}
