1	/**
2	 * Virtual piano keyboard for mouse-triggered notes.
3	 * 2-octave range (C3-B4) with black/white keys.
4	 * Neo-brutalist styling with thick borders.
5	 */
6	
7	import { useCallback, useRef } from "react";
8	import { tokens } from "@ui/tokens/tokens";
9	
10	type VirtualKeyboardProps = {
11	  onNoteOn: (note: number, velocity: number) => void;
12	  onNoteOff: (note: number) => void;
13	};
14	
15	const OCTAVE_START = 48; // C3
16	const NUM_OCTAVES = 2;
17	
18	/** White key indices within an octave (C D E F G A B) */
19	const WHITE_KEY_OFFSETS = [0, 2, 4, 5, 7, 9, 11];
20	/** Black key indices within an octave */
21	const BLACK_KEY_OFFSETS = [1, 3, 6, 8, 10];
22	/** Black key positions relative to white keys (0-indexed from C) */
23	const BLACK_KEY_POSITIONS = [0.7, 1.7, 3.7, 4.7, 5.7];
24	
25	const WHITE_KEY_WIDTH = 28;
26	const WHITE_KEY_HEIGHT = 80;
27	const BLACK_KEY_WIDTH = 18;
28	const BLACK_KEY_HEIGHT = 50;
29	
30	const WHITE_KEY_BORDER =
31	  String(tokens.border.width) + "px solid " + tokens.color.black;
32	const BLACK_KEY_BORDER =
33	  String(tokens.border.width) + "px solid " + tokens.color.gray700;
34	
35	export function VirtualKeyboard({
36	  onNoteOn,
37	  onNoteOff,
38	}: VirtualKeyboardProps): React.JSX.Element {
39	  const activeNotes = useRef(new Set<number>());
40	
41	  const handleMouseDown = useCallback(
42	    (note: number) => {
43	      if (!activeNotes.current.has(note)) {
44	        activeNotes.current.add(note);
45	        onNoteOn(note, 100);
46	      }
47	    },
48	    [onNoteOn],
49	  );
50	
51	  const handleMouseUp = useCallback(
52	    (note: number) => {
53	      if (activeNotes.current.has(note)) {
54	        activeNotes.current.delete(note);
55	        onNoteOff(note);
56	      }
57	    },
58	    [onNoteOff],
59	  );
60	
61	  const handleMouseLeave = useCallback(
62	    (note: number) => {
63	      if (activeNotes.current.has(note)) {
64	        activeNotes.current.delete(note);
65	        onNoteOff(note);
66	      }
67	    },
68	    [onNoteOff],
69	  );
70	
71	  const whiteKeys: React.JSX.Element[] = [];
72	  const blackKeys: React.JSX.Element[] = [];
73	
74	  let whiteIndex = 0;
75	
76	  for (let octave = 0; octave < NUM_OCTAVES; octave++) {
77	    for (const offset of WHITE_KEY_OFFSETS) {
78	      const note = OCTAVE_START + octave * 12 + offset;
79	      const x = whiteIndex * WHITE_KEY_WIDTH;
80	      whiteKeys.push(
81	        <div
82	          key={"w-" + String(note)}
83	          data-testid={"key-" + String(note)}
84	          onMouseDown={() => {
85	            handleMouseDown(note);
86	          }}
87	          onMouseUp={() => {
88	            handleMouseUp(note);
89	          }}
90	          onMouseLeave={() => {
91	            handleMouseLeave(note);
92	          }}
93	          style={{
94	            position: "absolute",
95	            left: x,
96	            top: 0,
97	            width: WHITE_KEY_WIDTH,
98	            height: WHITE_KEY_HEIGHT,
99	            backgroundColor: tokens.color.white,
100	            border: WHITE_KEY_BORDER,
101	            cursor: "pointer",
102	            userSelect: "none",
103	            zIndex: 1,
104	          }}
105	        />,
106	      );
107	      whiteIndex++;
108	    }
109	
110	    for (let bi = 0; bi < BLACK_KEY_OFFSETS.length; bi++) {
111	      const offset = BLACK_KEY_OFFSETS[bi] ?? 0;
112	      const pos = BLACK_KEY_POSITIONS[bi] ?? 0;
113	      const note = OCTAVE_START + octave * 12 + offset;
114	      const x =
115	        (octave * WHITE_KEY_OFFSETS.length + pos) * WHITE_KEY_WIDTH +
116	        (WHITE_KEY_WIDTH - BLACK_KEY_WIDTH) / 2;
117	
118	      blackKeys.push(
119	        <div
120	          key={"b-" + String(note)}
121	          data-testid={"key-" + String(note)}
122	          onMouseDown={() => {
123	            handleMouseDown(note);
124	          }}
125	          onMouseUp={() => {
126	            handleMouseUp(note);
127	          }}
128	          onMouseLeave={() => {
129	            handleMouseLeave(note);
130	          }}
131	          style={{
132	            position: "absolute",
133	            left: x,
134	            top: 0,
135	            width: BLACK_KEY_WIDTH,
136	            height: BLACK_KEY_HEIGHT,
137	            backgroundColor: tokens.color.black,
138	            border: BLACK_KEY_BORDER,
139	            cursor: "pointer",
140	            userSelect: "none",
141	            zIndex: 2,
142	          }}
143	        />,
144	      );
145	    }
146	  }
147	
148	  const totalWidth = whiteIndex * WHITE_KEY_WIDTH;
149	
150	  return (
151	    <div
152	      data-testid="virtual-keyboard"
153	      style={{
154	        position: "relative",
155	        width: totalWidth,
156	        height: WHITE_KEY_HEIGHT,
157	        flexShrink: 0,
158	      }}
159	    >
160	      {whiteKeys}
161	      {blackKeys}
162	    </div>
163	  );
164	}
