1	import type { UndoCommand } from "@state/undo/undo-command";
2	import { useDawStore } from "@state/store";
3	import { useArpeggiatorStore } from "@state/arpeggiator";
4	import { useAutomationStore } from "@state/automation";
5	import type { TrackModel, ClipModel } from "@state/track/types";
6	import type { ArpParams } from "@audio/arpeggiator/arpeggiator-types";
7	import type { AutomationLane } from "@audio/automation";
8	
9	function getStore(): ReturnType<typeof useDawStore.getState> {
10	  return useDawStore.getState();
11	}
12	
13	// ---------------------------------------------------------------------------
14	// AddTrackCommand / RemoveTrackCommand
15	// ---------------------------------------------------------------------------
16	
17	export class AddTrackCommand implements UndoCommand {
18	  readonly type = "add-track";
19	
20	  constructor(
21	    private readonly track: TrackModel,
22	    private readonly index?: number,
23	  ) {}
24	
25	  execute(): void {
26	    getStore().addTrack(this.track, this.index);
27	    useArpeggiatorStore.getState().initArp(this.track.id);
28	  }
29	
30	  undo(): void {
31	    useArpeggiatorStore.getState().removeArp(this.track.id);
32	    useAutomationStore.getState().removeTrackLanes(this.track.id);
33	    getStore().removeTrack(this.track.id);
34	  }
35	
36	  serialize(): Record<string, unknown> {
37	    return { track: this.track, index: this.index };
38	  }
39	}
40	
41	export class RemoveTrackCommand implements UndoCommand {
42	  readonly type = "remove-track";
43	
44	  private savedTrack: TrackModel | undefined;
45	  private savedClips: readonly ClipModel[] = [];
46	  private savedIndex = -1;
47	  private savedArpParams: ArpParams | undefined;
48	  private savedAutomationLanes: readonly AutomationLane[] = [];
49	
50	  constructor(private readonly trackId: string) {}
51	
52	  execute(): void {
53	    const state = getStore();
54	    this.savedIndex = state.tracks.findIndex((t) => t.id === this.trackId);
55	    this.savedTrack = state.tracks.find((t) => t.id === this.trackId);
56	
57	    if (this.savedTrack) {
58	      this.savedClips = this.savedTrack.clipIds
59	        .map((cid) => state.clips[cid])
60	        .filter((c): c is ClipModel => c !== undefined);
61	    }
62	
63	    this.savedArpParams = useArpeggiatorStore
64	      .getState()
65	      .getParams(this.trackId);
66	    this.savedAutomationLanes = useAutomationStore
67	      .getState()
68	      .getLanes(this.trackId);
69	    useArpeggiatorStore.getState().removeArp(this.trackId);
70	    useAutomationStore.getState().removeTrackLanes(this.trackId);
71	    state.removeTrack(this.trackId);
72	  }
73	
74	  undo(): void {
75	    if (this.savedTrack === undefined) return;
76	
77	    // Re-add the track at its original position (without clips first)
78	    const trackWithoutClips: TrackModel = { ...this.savedTrack, clipIds: [] };
79	    getStore().addTrack(trackWithoutClips, this.savedIndex);
80	    useArpeggiatorStore.getState().initArp(this.savedTrack.id);
81	    if (this.savedArpParams) {
82	      useArpeggiatorStore
83	        .getState()
84	        .setParams(this.savedTrack.id, this.savedArpParams);
85	    }
86	
87	    // Restore automation lanes
88	    if (this.savedAutomationLanes.length > 0) {
89	      useAutomationStore.setState((s) => ({
90	        lanes: {
91	          ...s.lanes,
92	          [this.trackId]: this.savedAutomationLanes,
93	        },
94	      }));
95	    }
96	
97	    // Re-add all clips (addClip also wires up clipIds)
98	    for (const clip of this.savedClips) {
99	      getStore().addClip(clip);
100	    }
101	  }
102	
103	  serialize(): Record<string, unknown> {
104	    return { trackId: this.trackId };
105	  }
106	}
107	
108	// ---------------------------------------------------------------------------
109	// UpdateTrackCommand
110	// ---------------------------------------------------------------------------
111	
112	export class UpdateTrackCommand implements UndoCommand {
113	  readonly type = "update-track";
114	
115	  private oldPatch: Partial<Omit<TrackModel, "id">> | undefined;
116	
117	  constructor(
118	    private readonly trackId: string,
119	    private readonly newPatch: Partial<Omit<TrackModel, "id">>,
120	  ) {}
121	
122	  execute(): void {
123	    const track = getStore().tracks.find((t) => t.id === this.trackId);
124	    if (track === undefined) return;
125	
126	    // Capture old values for only the keys being changed
127	    const old: Record<string, unknown> = {};
128	    for (const key of Object.keys(this.newPatch)) {
129	      old[key] = track[key as keyof TrackModel];
130	    }
131	    this.oldPatch = old as Partial<Omit<TrackModel, "id">>;
132	
133	    getStore().updateTrack(this.trackId, this.newPatch);
134	  }
135	
136	  undo(): void {
137	    if (this.oldPatch === undefined) return;
138	    getStore().updateTrack(this.trackId, this.oldPatch);
139	  }
140	
141	  serialize(): Record<string, unknown> {
142	    return {
143	      trackId: this.trackId,
144	      newPatch: this.newPatch,
145	      oldPatch: this.oldPatch,
146	    };
147	  }
148	}
