150	// ---------------------------------------------------------------------------
151	// ReorderTrackCommand
152	// ---------------------------------------------------------------------------
153	
154	export class ReorderTrackCommand implements UndoCommand {
155	  readonly type = "reorder-track";
156	
157	  private fromIndex = -1;
158	
159	  constructor(
160	    private readonly trackId: string,
161	    private readonly toIndex: number,
162	  ) {}
163	
164	  execute(): void {
165	    this.fromIndex = getStore().tracks.findIndex((t) => t.id === this.trackId);
166	    getStore().reorderTrack(this.trackId, this.toIndex);
167	  }
168	
169	  undo(): void {
170	    if (this.fromIndex === -1) return;
171	    getStore().reorderTrack(this.trackId, this.fromIndex);
172	  }
173	
174	  serialize(): Record<string, unknown> {
175	    return {
176	      trackId: this.trackId,
177	      fromIndex: this.fromIndex,
178	      toIndex: this.toIndex,
179	    };
180	  }
181	}
