183	// ---------------------------------------------------------------------------
184	// AddClipCommand / RemoveClipCommand
185	// ---------------------------------------------------------------------------
186	
187	export class AddClipCommand implements UndoCommand {
188	  readonly type = "add-clip";
189	
190	  constructor(private readonly clip: ClipModel) {}
191	
192	  execute(): void {
193	    getStore().addClip(this.clip);
194	  }
195	
196	  undo(): void {
197	    getStore().removeClip(this.clip.id);
198	  }
199	
200	  serialize(): Record<string, unknown> {
201	    return { clip: this.clip };
202	  }
