204	
205	export class RemoveClipCommand implements UndoCommand {
206	  readonly type = "remove-clip";
207	
208	  private savedClip: ClipModel | undefined;
209	
210	  constructor(private readonly clipId: string) {}
211	
212	  execute(): void {
213	    this.savedClip = getStore().clips[this.clipId];
214	    getStore().removeClip(this.clipId);
215	  }
216	
217	  undo(): void {
218	    if (this.savedClip === undefined) return;
