25	function useDrumMachineState(trackId: string): {
26	  pattern: DrumPattern;
27	  currentStep: number;
28	  params: Record<DrumInstrumentId, DrumInstrumentParams>;
29	  onToggleStep: (instrumentId: DrumInstrumentId, stepIndex: number) => void;
30	  onSetAccent: (stepIndex: number, accent: boolean) => void;
31	  onTriggerPad: (instrumentId: DrumInstrumentId) => void;
32	  onParamChange: (
33	    instrumentId: DrumInstrumentId,
34	    key: keyof DrumInstrumentParams,
35	    value: number,
36	  ) => void;
37	  onSwitchPattern: (name: string) => void;
38	  onClearPattern: () => void;
39	} {
40	  const transport = useTransport();
41	  const transportState = useDawStore((s) => s.transportState);
42	  const bpm = useDawStore((s) => s.bpm);
43	
44	  const seq = getOrCreateSequencer(trackId);
45	
46	  const [pattern, setPattern] = useState<DrumPattern>(() => seq.getPattern());
47	  const [liveStep, setLiveStep] = useState(0);
48	  const [params, setParams] = useState<
49	    Record<DrumInstrumentId, DrumInstrumentParams>
50	  >(() => getOrCreateParams(trackId));
51	
52	  // Sync pattern when trackId changes (sequencer instance changes)
53	  useEffect(() => {
54	    setPattern(seq.getPattern());
55	  }, [seq]);
56	
57	  // Transport sync: advance step indicator when playing
58	  const rafRef = useRef(0);
59	  useEffect(() => {
60	    if (transportState !== "playing") return;
61	
62	    const clock = transport.getClock();
63	    if (!clock) return;
64	
65	    const stepsPerBeat = 4; // 16th notes
66	    let lastStep = -1;
67	
68	    const tick = (): void => {
69	      const cursor = clock.getCursorSeconds();
70	      const stepDuration = 60 / (bpm * stepsPerBeat);
71	      const step = Math.floor(cursor / stepDuration) % pattern.steps.length;
72	      if (step !== lastStep) {
73	        lastStep = step;
74	        setLiveStep(step);
75	      }
76	      rafRef.current = requestAnimationFrame(tick);
77	    };
78	    rafRef.current = requestAnimationFrame(tick);
79	
80	    return () => {
81	      cancelAnimationFrame(rafRef.current);
82	    };
83	  }, [transportState, transport, bpm, pattern.steps.length]);
84	
85	  // Audio scheduling is handled persistently by DrumSchedulerService
86	  // in TrackAudioBridgeProvider (not here, so it survives track deselection).
87	
88	  // Derive currentStep: 0 when stopped, liveStep when playing/paused
89	  const currentStep = transportState === "stopped" ? 0 : liveStep;
90	
91	  const onToggleStep = useCallback(
92	    (instrumentId: DrumInstrumentId, stepIndex: number) => {
93	      seq.toggleStep(instrumentId, stepIndex);
94	      setPattern(seq.getPattern());
95	    },
96	    [seq],
97	  );
98	
99	  const onSetAccent = useCallback(
100	    (stepIndex: number, accent: boolean) => {
101	      seq.setAccent(stepIndex, accent);
102	      setPattern(seq.getPattern());
103	    },
104	    [seq],
105	  );
106	
107	  const bridge = useTrackAudioBridge();
108	  const onTriggerPad = useCallback(
109	    (instrumentId: DrumInstrumentId) => {
110	      const kit = bridge.getDrumKit(trackId);
111	      kit?.trigger(instrumentId, 0, 1);
112	    },
113	    [bridge, trackId],
114	  );
115	
116	  const onParamChange = useCallback(
117	    (
118	      instrumentId: DrumInstrumentId,
119	      key: keyof DrumInstrumentParams,
120	      value: number,
121	    ) => {
122	      // Forward to audio engine
123	      const kit = bridge.getDrumKit(trackId);
124	      kit?.setParam(instrumentId, key, value);
125	
126	      setParams((prev) => {
127	        const next = {
128	          ...prev,
129	          [instrumentId]: { ...prev[instrumentId], [key]: value },
130	        };
131	        paramsCache.set(trackId, next);
132	        return next;
133	      });
134	    },
135	    [bridge, trackId],
136	  );
137	
138	  const onSwitchPattern = useCallback(
139	    (name: string) => {
140	      seq.switchPattern(name);
141	      setPattern(seq.getPattern());
142	    },
143	    [seq],
144	  );
145	
146	  const onClearPattern = useCallback(() => {
147	    seq.clearPattern();
148	    setPattern(seq.getPattern());
149	  }, [seq]);
150	
151	  return {
152	    pattern,
153	    currentStep,
154	    params,
155	    onToggleStep,
156	    onSetAccent,
157	    onTriggerPad,
158	    onParamChange,
159	    onSwitchPattern,
160	    onClearPattern,
161	  };
162	}
