390	// ─── Automation scheduling ───
391	
392	function scheduleAutomation(
393	  ctx: OfflineAudioContext,
394	  lanes: readonly AutomationLane[],
395	  mixer: OfflineMixer,
396	  rangeStart: number,
397	  duration: number,
398	): void {
399	  for (const lane of lanes) {
400	    if (!lane.armed || lane.mode === "write" || lane.points.length === 0)
401	      continue;
402	
403	    const strip = mixer.strips.get(lane.trackId);
404	    if (!strip) continue;
405	
406	    // Resolve target parameter
407	    const resolved = resolveOfflineParam(lane, strip);
408	    if (!resolved) continue;
409	
410	    const { param, range } = resolved;
411	
412	    // Schedule automation for the full render duration
413	    const startNorm = evaluateCurve(lane.points, rangeStart);
414	    const startVal = denormalize(startNorm, range);
415	    param.setValueAtTime(startVal, 0);
416	
417	    // Schedule breakpoints
418	    const innerPoints = findPointsInRange(
419	      lane.points,
420	      rangeStart,
421	      rangeStart + duration,
422	    );
423	    for (const pt of innerPoints) {
424	      const ctxTime = pt.time - rangeStart;
425	      const val = denormalize(pt.value, range);
426	      param.linearRampToValueAtTime(val, ctxTime);
427	    }
428	
429	    // End value
430	    const endNorm = evaluateCurve(lane.points, rangeStart + duration);
431	    const endVal = denormalize(endNorm, range);
432	    param.linearRampToValueAtTime(endVal, duration);
433	  }
434	}
435	
436	type ResolvedOfflineParam = {
437	  param: AudioParam;
438	  range: { min: number; max: number };
439	};
440	
441	function resolveOfflineParam(
442	  lane: AutomationLane,
443	  strip: OfflineMixerStrip,
444	): ResolvedOfflineParam | undefined {
445	  // Only mixer volume/pan automation is applied offline.
446	  // Synth-parameter and drum-parameter lanes are silently skipped.
447	  if (lane.target.type !== "mixer") return undefined;
448	
449	  switch (lane.target.param) {
450	    case "volume":
451	      return { param: strip.faderGain.gain, range: { min: 0, max: 2 } };
452	    case "pan":
453	      return { param: strip.panner.pan, range: { min: -1, max: 1 } };
454	  }
455	}
456	
457	// ─── WAV encoding (chunked) ───
458	
459	/** ~30 seconds of samples per encoding chunk (adapts to actual sample rate) */
460	const WAV_CHUNK_SECONDS = 30;
461	
462	function encodeRenderedBuffer(
463	  buffer: AudioBuffer,
464	  bitDepth: 16 | 24 | 32,
465	): Blob {
466	  const numChannels = Math.min(buffer.numberOfChannels, 2);
467	  const totalSamples = buffer.length;
468	  const sampleRate = buffer.sampleRate;
469	  const chunkSamples = WAV_CHUNK_SECONDS * sampleRate;
470	
471	  const channelData: Float32Array[] = [];
472	  for (let c = 0; c < numChannels; c++) {
473	    channelData.push(buffer.getChannelData(c));
474	  }
475	
476	  const header = encodeWavHeader(
477	    numChannels,
478	    sampleRate,
479	    bitDepth,
480	    totalSamples,
481	  );
482	  const chunks: ArrayBuffer[] = [];
483	
484	  // Encode in chunks for memory efficiency
485	  for (let offset = 0; offset < totalSamples; offset += chunkSamples) {
486	    const end = Math.min(offset + chunkSamples, totalSamples);
487	    const chunkChannels = channelData.map((ch) => ch.subarray(offset, end));
488	    chunks.push(encodePcmChunk(chunkChannels, bitDepth));
489	  }
490	
491	  return assembleWav(header, chunks);
492	}
493	
494	// ─── BounceEngine factory ───
495	
496	type OfflineContextFactory = (
497	  duration: number,
498	  sampleRate: number,
499	) => OfflineAudioContext;
500	
501	const defaultContextFactory: OfflineContextFactory = (duration, sampleRate) => {
502	  const length = Math.ceil(duration * sampleRate);
503	  return new OfflineAudioContext(2, length, sampleRate);
504	};
505	
506	export function createBounceEngine(
507	  contextFactory: OfflineContextFactory = defaultContextFactory,
508	): BounceEngine {
509	  // Cancellation state — checked at yield/await suspension points
510	  let cancelFlag = false;
511	  let bouncing = false;
512	  // Indirection prevents the linter from proving the flag is always falsy
513	  // (it changes externally via cancel() between yield/await suspensions)
514	  function isCancelled(): boolean {
515	    return cancelFlag;
516	  }
517	
518	  return {
519	    async *bounce(
520	      options: BounceOptions,
521	    ): AsyncGenerator<BounceProgress, BounceResult> {
522	      if (bouncing) {
523	        throw new Error(
524	          "BounceEngine: bounce() called while another bounce is active. " +
525	            "Cancel or drain the previous generator first.",
526	        );
527	      }
528	      bouncing = true;
529	      cancelFlag = false;
530	
531	      if (options.sampleRate <= 0) {
532	        bouncing = false;
533	        throw new Error(
534	          `BounceEngine: invalid sampleRate ${String(options.sampleRate)}`,
535	        );
536	      }
537	
538	      try {
539	        const emptyResult: BounceResult = {
540	          blob: new Blob(),
541	          duration: 0,
542	          sampleRate: options.sampleRate,
543	          channels: 2,
544	        };
545	
546	        // Phase: Preparing
547	        yield {
548	          phase: "preparing",
549	          progress: 0,
550	          renderedSeconds: 0,
551	          totalSeconds: 0,
552	        };
553	
554	        if (isCancelled()) return emptyResult;
555	
556	        // Determine render range
557	        const sessionBounds = computeSessionBounds(
558	          options.tracks,
559	          options.clips,
560	        );
561	        let rangeStart: number;
562	        let rangeEnd: number;
563	
564	        if (options.range.type === "region") {
565	          rangeStart = options.range.start;
566	          rangeEnd = options.range.end;
567	        } else {
568	          rangeStart = sessionBounds.start;
569	          rangeEnd = sessionBounds.end;
570	        }
571	
572	        const duration = Math.max(0, rangeEnd - rangeStart);
573	        if (duration === 0) return emptyResult;
574	
575	        // Build event timeline
576	        const timeline = buildEventTimeline(options.tracks, options.clips);
577	        const audibleIds = getAudibleTrackIds(options.tracks);
578	
579	        // Phase: Rendering
580	        yield {
581	          phase: "rendering",
582	          progress: 0.1,
583	          renderedSeconds: 0,
584	          totalSeconds: duration,
585	        };
586	
587	        // Create OfflineAudioContext
588	        const ctx = contextFactory(duration, options.sampleRate);
589	
590	        // Build offline mixer graph
591	        const mixer = buildOfflineMixer(
592	          ctx,
593	          options.tracks,
594	          options.masterLevel,
595	          audibleIds,
596	        );
597	
598	        // Schedule audio clips
599	        scheduleAudioClips(
600	          ctx,
601	          timeline.audioClips,
602	          mixer,
603	          rangeStart,
604	          options.getBuffer,
605	        );
606	
607	        // Schedule MIDI clips (pre-rendered synth)
608	        scheduleMidiClips(
609	          ctx,
610	          timeline.midiClips,
611	          mixer,
612	          rangeStart,
613	          options.instruments,
614	        );
615	
616	        // Schedule drum clips
617	        scheduleDrumClips(
618	          ctx,
619	          timeline.midiClips,
620	          mixer,
621	          rangeStart,
622	          options.instruments,
623	        );
624	
625	        // Schedule automation
626	        scheduleAutomation(
627	          ctx,
628	          options.automationLanes,
629	          mixer,
630	          rangeStart,
631	          duration,
632	        );
633	
634	        if (isCancelled()) return emptyResult;
635	
636	        // Note: startRendering() blocks until the entire offline render completes.
637	        // Cancellation checks only run at yield boundaries, so a long render
638	        // (e.g. 10 min at 96kHz) cannot be interrupted mid-render.
639	        const renderedBuffer = await ctx.startRendering();
640	
641	        yield {
642	          phase: "rendering",
643	          progress: 0.7,
644	          renderedSeconds: duration,
645	          totalSeconds: duration,
646	        };
647	
648	        if (isCancelled()) return emptyResult;
649	
650	        // Phase: Encoding
651	        yield {
652	          phase: "encoding",
653	          progress: 0.8,
654	          renderedSeconds: duration,
655	          totalSeconds: duration,
656	        };
657	
658	        const blob = encodeRenderedBuffer(renderedBuffer, options.bitDepth);
659	
660	        yield {
661	          phase: "complete",
662	          progress: 1,
663	          renderedSeconds: duration,
664	          totalSeconds: duration,
665	        };
666	
667	        return {
668	          blob,
669	          duration,
670	          sampleRate: options.sampleRate,
671	          channels: 2,
672	        };
673	      } finally {
674	        bouncing = false;
675	      }
676	    },
677	
678	    cancel(): void {
679	      cancelFlag = true;
680	    },
681	  };
682	}
