226	function drawClips(rc: RenderContext): void {
227	  const { ctx, view, tracks, clips, selectedClipIds } = rc;
228	  const selectedSet = new Set(selectedClipIds);
229	
230	  for (let i = 0; i < tracks.length; i++) {
231	    const track = tracks[i];
232	    if (track === undefined) continue;
233	    const y = trackY(i, view);
234	
235	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
236	
237	    for (const clipId of track.clipIds) {
238	      const clip = clips[clipId];
239	      if (clip === undefined) continue;
240	
241	      const x = secondsToX(clip.startTime, view);
242	      const w = clip.duration * view.pixelsPerSecond;
243	
244	      // Skip clips that are fully out of view
245	      if (x + w < view.headerWidth || x > rc.width) continue;
