260	          ctx.rect(x, clipY, w, clipH);
261	          ctx.clip();
262	
263	          ctx.fillStyle = "rgba(255,255,255,0.4)";
264	          const mid = clipY + clipH / 2;
265	          const halfH = clipH / 2;
266	          const barWidth = Math.max(1, w / peakData.length);
267	
268	          for (let p = 0; p < peakData.length; p++) {
269	            const min = peakData.peaks[p * 2];
270	            const max = peakData.peaks[p * 2 + 1];
271	            if (min === undefined || max === undefined) continue;
272	            const px = x + (p / peakData.length) * w;
273	            const top = mid - max * halfH;
274	            const bottom = mid - min * halfH;
275	            ctx.fillRect(px, top, barWidth, bottom - top);
276	          }
277	
278	          ctx.restore();
279	        }
280	      }
281	
282	      // Clip border
283	      const isSelected = selectedSet.has(clip.id);
284	      ctx.strokeStyle = isSelected ? COLOR.white : track.color;
285	      ctx.lineWidth = BORDER_WIDTH;
286	      ctx.strokeRect(x, clipY, w, clipH);
287	
288	      // Clip name label
289	      ctx.save();
290	      ctx.beginPath();
291	      ctx.rect(x, clipY, w, clipH);
292	      ctx.clip();
293	      ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
294	      ctx.fillStyle = COLOR.white;
295	      ctx.textBaseline = "top";
296	      ctx.textAlign = "left";
297	      ctx.fillText(clip.name, x + 4, clipY + 4);
298	      ctx.restore();
299	    }
300	  }
301	}
302	
303	const AUTOMATION_LINE_COLOR = "#00ccff";
304	const AUTOMATION_POINT_RADIUS = 3;
305	const AUTOMATION_SAMPLES_PER_PX = 4; // evaluate every 4 pixels for smooth curves
306	
307	function drawAutomationLanes(rc: RenderContext): void {
308	  const { ctx, view, tracks, automationLanes } = rc;
309	  if (!automationLanes) return;
310	
311	  for (let i = 0; i < tracks.length; i++) {
312	    const track = tracks[i];
313	    if (track === undefined) continue;
314	    const lanes = automationLanes[track.id];
315	    if (!lanes || lanes.length === 0) continue;
316	
317	    const y = trackY(i, view);
318	    const laneBottom = y + view.trackHeight;
319	    if (laneBottom < RULER_HEIGHT || y > rc.height) continue;
320	
321	    for (const lane of lanes) {
322	      if (lane.points.length === 0) continue;
323	
324	      ctx.save();
325	
326	      // Clip to track lane area (past the header)
327	      ctx.beginPath();
328	      ctx.rect(
329	        view.headerWidth,
330	        y + CLIP_PADDING,
331	        rc.width - view.headerWidth,
332	        view.trackHeight - CLIP_PADDING * 2,
333	      );
334	      ctx.clip();
335	
336	      // Draw the curve as connected line segments
337	      const startSec = view.scrollX;
338	      const endSec =
339	        view.scrollX + (rc.width - view.headerWidth) / view.pixelsPerSecond;
340	      const step = AUTOMATION_SAMPLES_PER_PX / view.pixelsPerSecond;
341	      const laneH = view.trackHeight - CLIP_PADDING * 2;
342	      const laneTop = y + CLIP_PADDING;
343	
344	      ctx.strokeStyle = AUTOMATION_LINE_COLOR;
345	      ctx.lineWidth = 1.5;
346	      ctx.beginPath();
347	
348	      let first = true;
349	      for (let t = startSec; t <= endSec; t += step) {
350	        const val = evaluateCurve(lane.points, t);
351	        const px = secondsToX(t, view);
352	        const py = laneTop + laneH * (1 - val); // 1.0 at top, 0.0 at bottom
353	        if (first) {
354	          ctx.moveTo(px, py);
355	          first = false;
356	        } else {
357	          ctx.lineTo(px, py);
358	        }
359	      }
360	      ctx.stroke();
361	
362	      // Draw point handles
363	      ctx.fillStyle = AUTOMATION_LINE_COLOR;
364	      for (const pt of lane.points) {
365	        const px = secondsToX(pt.time, view);
366	        const py = laneTop + laneH * (1 - pt.value);
367	        if (px < view.headerWidth || px > rc.width) continue;
368	
369	        ctx.beginPath();
370	        ctx.arc(px, py, AUTOMATION_POINT_RADIUS, 0, Math.PI * 2);
371	        ctx.fill();
372	      }
373	
374	      ctx.restore();
375	    }
376	  }
377	}
378	
379	function drawPlayhead(rc: RenderContext): void {
380	  const { ctx, height, view, cursorSeconds } = rc;
381	  const x = secondsToX(cursorSeconds, view);
382	
383	  if (x < view.headerWidth || x > rc.width) return;
384	
385	  ctx.strokeStyle = COLOR.red;
386	  ctx.lineWidth = 2;
387	  ctx.beginPath();
388	  ctx.moveTo(x, 0);
389	  ctx.lineTo(x, height);
390	  ctx.stroke();
391	}
392	
393	// -- Public API ---------------------------------------------------------------
394	
395	export function renderArrangement(rc: RenderContext): void {
396	  drawBackground(rc);
397	  drawTimeRuler(rc);
398	  drawGrid(rc);
399	  drawTrackLanes(rc);
400	  drawTrackHeaders(rc);
401	  drawClips(rc);
402	  drawAutomationLanes(rc);
403	  drawPlayhead(rc);
404	}
