49	  const transport = useTransport();
50	  const sabCursorRef = useTransportCursor(transport.getTransportSAB());
51	
52	  const handleDragOver = useCallback(
53	    (e: React.DragEvent<HTMLCanvasElement>): void => {
54	      if (!e.dataTransfer.types.includes("application/x-media-pool-source"))
55	        return;
56	
57	      const rect = e.currentTarget.getBoundingClientRect();
58	      const y = e.clientY - rect.top;
59	      const trackIndex = Math.floor(
60	        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
61	      );
62	      const state = useDawStore.getState();
63	      const track = trackIndex >= 0 ? state.tracks[trackIndex] : undefined;
64	      if (track !== undefined && track.type === "audio") {
65	        e.preventDefault();
66	        e.dataTransfer.dropEffect = "copy";
67	      }
68	    },
69	    [view],
70	  );
71	
72	  const handleDrop = useCallback(
73	    (e: React.DragEvent<HTMLCanvasElement>): void => {
74	      const raw = e.dataTransfer.getData("application/x-media-pool-source");
75	      if (!raw) return;
76	      e.preventDefault();
77	
78	      let parsed: unknown;
79	      try {
80	        parsed = JSON.parse(raw);
81	      } catch {
82	        return;
83	      }
84	      const data = parsed as Record<string, unknown>;
85	      if (
86	        typeof data.sourceId !== "string" ||
87	        typeof data.name !== "string" ||
88	        typeof data.durationSeconds !== "number"
89	      )
90	        return;
91	
92	      const rect = e.currentTarget.getBoundingClientRect();
93	      const x = e.clientX - rect.left;
94	      const y = e.clientY - rect.top;
95	
96	      const state = useDawStore.getState();
97	      const trackIndex = Math.floor(
98	        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
99	      );
100	      if (trackIndex < 0) return;
101	      const track = state.tracks[trackIndex];
102	      if (track === undefined || track.type !== "audio") return;
103	
104	      const dropTime = snapToGrid(
105	        Math.max(0, xToSeconds(x, view)),
106	        bpmForDrop,
107	        gridSnap,
108	      );
109	
110	      const clip: AudioClipModel = {
111	        type: "audio",
112	        id: "clip-" + crypto.randomUUID(),
113	        trackId: track.id,
114	        sourceId: data.sourceId,
115	        startTime: dropTime,
116	        sourceOffset: 0,
117	        duration: data.durationSeconds,
118	        gain: 1,
119	        fadeIn: 0,
120	        fadeOut: 0,
121	        name: data.name,
122	      };
123	
124	      const cmd = new AddClipCommand(clip);
125	      cmd.execute();
126	      sharedUndoManager.push(cmd);
127	    },
128	    [view, gridSnap, bpmForDrop],
129	  );
130	
131	  const tracks = useDawStore((s) => s.tracks);
132	  const clips = useDawStore((s) => s.clips);
133	  const selectedClipIds = useDawStore((s) => s.selectedClipIds);
134	  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
135	  const bpm = useDawStore((s) => s.bpm);
136	  const transportState = useDawStore((s) => s.transportState);
137	  const automationLanes = useAutomationStore((s) => s.lanes);
138	  const pool = useMediaPool();
139	  const engine = useAudioEngine();
140	
141	  // Fetch and slice waveform peaks per audio clip
142	  const SAMPLES_PER_PEAK = 256;
143	  const [clipPeaks, setClipPeaks] = useState<
144	    Record<string, { peaks: Float32Array; length: number }>
145	  >({});
146	
147	  useEffect(() => {
148	    let cancelled = false;
149	    const sampleRate = engine.ctx.sampleRate;
150	
151	    async function fetchPeaks(): Promise<void> {
152	      const result: Record<string, { peaks: Float32Array; length: number }> =
153	        {};
154	      for (const clip of Object.values(clips)) {
155	        if (!isAudioClip(clip)) continue;
156	        const wp = await pool.getPeaks(clip.sourceId, SAMPLES_PER_PEAK);
157	        if (cancelled) return;
158	        if (!wp || wp.length === 0) continue;
159	
160	        // Slice peaks to match clip's sourceOffset and duration
161	        const startPeak = Math.floor(
162	          (clip.sourceOffset * sampleRate) / wp.samplesPerPeak,
163	        );
164	        const peakCount = Math.ceil(
165	          (clip.duration * sampleRate) / wp.samplesPerPeak,
166	        );
167	        const endPeak = Math.min(startPeak + peakCount, wp.length);
168	        const sliceLen = Math.max(0, endPeak - startPeak);
169	
170	        result[clip.id] = {
171	          peaks: wp.peaks.slice(startPeak * 2, endPeak * 2),
172	          length: sliceLen,
173	        };
174	      }
175	      if (!cancelled) setClipPeaks(result);
176	    }
177	
178	    void fetchPeaks();
179	    return () => {
180	      cancelled = true;
181	    };
182	  }, [clips, pool, engine.ctx.sampleRate]);
183	
184	  // Render the arrangement canvas
185	  const render = useCallback((): void => {
186	    const canvas = canvasRef.current;
187	    if (canvas === null) return;
188	    const ctx = canvas.getContext("2d");
189	    if (ctx === null) return;
190	    const rect = canvas.getBoundingClientRect();
191	    renderArrangement({
192	      ctx,
193	      width: rect.width,
194	      height: rect.height,
195	      view,
196	      tracks,
197	      clips,
198	      selectedClipIds,
199	      cursorSeconds,
200	      bpm,
201	      automationLanes,
202	      clipPeaks,
203	    });
204	  }, [
205	    view,
206	    tracks,
207	    clips,
208	    selectedClipIds,
209	    cursorSeconds,
210	    bpm,
211	    automationLanes,
212	    clipPeaks,
213	  ]);
214	
215	  // Schedule re-render when state changes or during playback.
216	  // During playback, read cursor from SAB (updated by audio thread) to keep
217	  // the playback cursor moving smoothly.
218	  useEffect(() => {
219	    if (transportState !== "playing") {
220	      render();
221	      return;
222	    }
223	
224	    const tick = (): void => {
225	      const canvas = canvasRef.current;
226	      if (canvas !== null) {
227	        const ctx = canvas.getContext("2d");
228	        if (ctx !== null) {
229	          const rect = canvas.getBoundingClientRect();
230	          renderArrangement({
231	            ctx,
232	            width: rect.width,
233	            height: rect.height,
234	            view,
235	            tracks,
236	            clips,
237	            selectedClipIds,
238	            cursorSeconds: sabCursorRef.current,
239	            bpm,
240	            automationLanes,
241	            clipPeaks,
242	          });
243	        }
244	      }
245	      rafRef.current = requestAnimationFrame(tick);
246	    };
247	
248	    rafRef.current = requestAnimationFrame(tick);
249	    return (): void => {
250	      cancelAnimationFrame(rafRef.current);
251	    };
252	    // eslint-disable-next-line react-hooks/exhaustive-deps -- RAF loop reads SAB directly; deps trigger effect restart on state changes
253	  }, [render, transportState]);
254	
255	  // Handle canvas sizing with ResizeObserver
256	  useEffect(() => {
257	    const canvas = canvasRef.current;
258	    if (canvas === null) return;
259	    const parent = canvas.parentElement;
260	    if (parent === null) return;
261	
262	    const resizeCanvas = (): void => {
263	      const dpr = window.devicePixelRatio;
264	      const rect = parent.getBoundingClientRect();
265	      canvas.width = rect.width * dpr;
266	      canvas.height = rect.height * dpr;
267	      canvas.style.width = `${String(rect.width)}px`;
268	      canvas.style.height = `${String(rect.height)}px`;
269	
270	      const ctx = canvas.getContext("2d");
271	      if (ctx !== null) {
272	        ctx.scale(dpr, dpr);
273	      }
274	    };
275	
276	    if (typeof ResizeObserver === "undefined") return;
277	
278	    const observer = new ResizeObserver(resizeCanvas);
279	    observer.observe(parent);
280	    resizeCanvas();
281	
282	    return (): void => {
283	      observer.disconnect();
284	    };
285	  }, []);
286	
287	  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
288	  const handleWheel = useCallback(
289	    (e: React.WheelEvent<HTMLCanvasElement>): void => {
290	      e.preventDefault();
291	
292	      if (e.ctrlKey || e.metaKey) {
293	        // Zoom
294	        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
295	        setView((prev) => ({
296	          ...prev,
297	          pixelsPerSecond: Math.min(
298	            MAX_PPS,
299	            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
300	          ),
301	        }));
302	      } else if (e.shiftKey) {
303	        // Horizontal scroll
304	        setView((prev) => ({
305	          ...prev,
306	          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
307	        }));
308	      } else {
309	        // Vertical scroll
310	        setView((prev) => ({
311	          ...prev,
312	          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
313	          scrollY: Math.max(0, prev.scrollY + e.deltaY),
314	        }));
315	      }
316	    },
317	    [],
318	  );
319	
320	  return (
321	    <section data-testid="arrangement-panel" className={styles["container"]}>
322	      <span id="arrangement-keys" hidden>
323	        Scroll: mouse wheel. Horizontal scroll: Shift + wheel. Zoom: Ctrl/Cmd +
324	        wheel. Double-click to create clip. Click to select. Drag to move clips.
325	      </span>
326	      <canvas
327	        ref={canvasRef}
328	        role="application"
329	        aria-label="Arrangement timeline"
330	        aria-describedby="arrangement-keys"
331	        className={styles["canvas"]}
332	        style={{ cursor: interactions.cursor }}
333	        onWheel={handleWheel}
334	        onPointerDown={interactions.onPointerDown}
335	        onPointerMove={interactions.onPointerMove}
336	        onPointerUp={interactions.onPointerUp}
337	        onDoubleClick={interactions.onDoubleClick}
338	        onDragOver={handleDragOver}
339	        onDrop={handleDrop}
340	      />
341	    </section>
342	  );
343	}
