1	/**
2	 * Module-level caches for drum machine sequencers and instrument parameters.
3	 * Extracted to avoid circular dependencies between panels.tsx and TrackAudioBridgeProvider.
4	 */
5	
6	import { createStepSequencer, type StepSequencer } from "./step-sequencer";
7	import {
8	  DRUM_INSTRUMENTS,
9	  DEFAULT_INSTRUMENT_PARAMS,
10	  type DrumInstrumentId,
11	  type DrumInstrumentParams,
12	} from "./drum-types";
13	import type { TrackAudioBridge } from "@audio/track-audio-bridge";
14	import { useDawStore } from "@state/store";
15	
16	export const sequencerCache = new Map<string, StepSequencer>();
17	export const paramsCache = new Map<
18	  string,
19	  Record<DrumInstrumentId, DrumInstrumentParams>
20	>();
21	
22	// Module-level bridge reference for trigger callbacks
23	let bridgeRef: TrackAudioBridge | null = null;
24	
25	export function setBridgeRef(bridge: TrackAudioBridge | null): void {
26	  bridgeRef = bridge;
27	}
28	
29	export function getOrCreateSequencer(trackId: string): StepSequencer {
30	  let seq = sequencerCache.get(trackId);
31	  if (!seq) {
32	    seq = createStepSequencer((trigger) => {
33	      const bridge = bridgeRef;
34	      if (!bridge) return;
35	      const kit = bridge.getDrumKit(trackId);
36	      kit?.trigger(
37	        trigger.instrumentId,
38	        trigger.time,
39	        trigger.velocity,
40	        trigger.flamMs,
41	      );
42	    });
43	    sequencerCache.set(trackId, seq);
44	  }
45	  return seq;
46	}
47	
48	export function getOrCreateParams(
49	  trackId: string,
50	): Record<DrumInstrumentId, DrumInstrumentParams> {
51	  let cached = paramsCache.get(trackId);
52	  if (!cached) {
53	    cached = {} as Record<DrumInstrumentId, DrumInstrumentParams>;
54	    for (const inst of DRUM_INSTRUMENTS) {
55	      cached[inst.id] = { ...DEFAULT_INSTRUMENT_PARAMS[inst.id] };
56	    }
57	    paramsCache.set(trackId, cached);
58	  }
59	  return cached;
60	}
61	
62	// Clean up caches when tracks are removed
63	let prevTrackIds = new Set(useDawStore.getState().tracks.map((t) => t.id));
64	useDawStore.subscribe((state) => {
65	  const trackIds = new Set(state.tracks.map((t) => t.id));
66	  for (const id of prevTrackIds) {
67	    if (!trackIds.has(id)) {
68	      sequencerCache.delete(id);
69	      paramsCache.delete(id);
70	    }
71	  }
72	  prevTrackIds = trackIds;
73	});
