107	export const useDawStore = create<DawStore>()((set, get) => ({
108	  // Transport defaults
109	  transportState: "stopped",
110	  bpm: 120,
111	  cursorSeconds: 0,
112	  loopEnabled: false,
113	  loopStart: 0,
114	  loopEnd: 0,
115	
116	  // Engine defaults
117	  engineStatus: "uninitialized",
118	
119	  // Mixer defaults
120	  masterVolume: 1,
121	
122	  // Track & clip defaults
123	  tracks: [],
124	  clips: {},
125	  selectedTrackIds: [],
126	  selectedClipIds: [],
127	  selectedNoteIds: [],
128	
129	  // Transport actions
130	  play: () => {
131	    set({ transportState: "playing" });
132	  },
133	  pause: () => {
134	    set({ transportState: "paused" });
135	  },
136	  stop: () => {
137	    set({ transportState: "stopped", cursorSeconds: 0 });
138	  },
139	  setBpm: (bpm: number) => {
140	    const clamped = Math.min(999, Math.max(20, bpm));
141	    if (!Number.isFinite(clamped)) return;
142	    set({ bpm: clamped });
143	  },
144	  setCursor: (seconds: number) => {
145	    set({ cursorSeconds: seconds });
146	  },
147	  setLoop: (enabled: boolean, start?: number, end?: number) => {
148	    set((state) => ({
149	      loopEnabled: enabled,
150	      loopStart: start ?? state.loopStart,
151	      loopEnd: end ?? state.loopEnd,
152	    }));
153	  },
154	
155	  // Engine actions
156	  setEngineStatus: (status: AudioEngineStatus) => {
157	    set({ engineStatus: status });
158	  },
159	
160	  // Mixer actions
161	  setMasterVolume: (volume: number) => {
162	    const clamped = Math.min(2, Math.max(0, volume));
163	    set({ masterVolume: clamped });
164	  },
165	
166	  // Track actions
167	  addTrack: (track: TrackModel, index?: number) => {
168	    set((state) => {
169	      const next = [...state.tracks];
170	      if (index !== undefined) {
171	        next.splice(index, 0, track);
172	      } else {
173	        next.push(track);
174	      }
175	      return { tracks: next };
176	    });
177	  },
178	
179	  removeTrack: (id: string) => {
180	    set((state) => {
181	      const track = state.tracks.find((t) => t.id === id);
182	      if (!track) return state;
183	      const removeSet = new Set(track.clipIds);
184	      const nextClips = Object.fromEntries(
185	        Object.entries(state.clips).filter(([k]) => !removeSet.has(k)),
186	      );
187	      return {
188	        tracks: state.tracks.filter((t) => t.id !== id),
189	        clips: nextClips,
190	      };
191	    });
192	  },
193	
194	  updateTrack: (id: string, patch: Partial<Omit<TrackModel, "id">>) => {
195	    set((state) => ({
196	      tracks: state.tracks.map((t) => (t.id === id ? { ...t, ...patch } : t)),
197	    }));
198	  },
199	
200	  reorderTrack: (id: string, toIndex: number) => {
201	    set((state) => {
202	      const fromIndex = state.tracks.findIndex((t) => t.id === id);
203	      if (fromIndex === -1) return state;
204	      const next = [...state.tracks];
205	      const moved = next.splice(fromIndex, 1)[0];
206	      if (moved === undefined) return state;
207	      next.splice(toIndex, 0, moved);
208	      return { tracks: next };
209	    });
210	  },
211	
212	  // Clip actions
213	  addClip: (clip: ClipModel) => {
214	    set((state) => {
215	      const nextClips = { ...state.clips, [clip.id]: clip };
216	      const tracks = state.tracks.map((t) =>
217	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
218	      );
219	      return { clips: nextClips, tracks };
220	    });
221	  },
222	
223	  removeClip: (id: string) => {
224	    set((state) => {
225	      const clip = state.clips[id];
226	      if (!clip) return state;
227	      const nextClips = Object.fromEntries(
228	        Object.entries(state.clips).filter(([k]) => k !== id),
229	      );
230	      const tracks = state.tracks.map((t) =>
231	        t.id === clip.trackId
232	          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
233	          : t,
234	      );
235	      return { clips: nextClips, tracks };
236	    });
237	  },
238	
239	  moveClip: (id: string, startTime: number, toTrackId?: string) => {
240	    set((state) => {
241	      const clip = state.clips[id];
242	      if (!clip) return state;
243	      // Validate target track exists
244	      if (
245	        toTrackId !== undefined &&
246	        !state.tracks.some((t) => t.id === toTrackId)
247	      ) {
248	        return state;
249	      }
250	      const updatedClip = {
251	        ...clip,
252	        startTime,
253	        trackId: toTrackId ?? clip.trackId,
254	      };
255	      const nextClips = { ...state.clips, [id]: updatedClip };
256	
257	      let tracks = state.tracks;
258	      if (toTrackId !== undefined && toTrackId !== clip.trackId) {
259	        tracks = tracks.map((t) => {
260	          if (t.id === clip.trackId) {
261	            return { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) };
262	          }
263	          if (t.id === toTrackId) {
264	            return { ...t, clipIds: [...t.clipIds, id] };
265	          }
266	          return t;
267	        });
268	      }
269	      return { clips: nextClips, tracks };
270	    });
271	  },
272	
273	  splitClip: (
274	    id: string,
275	    atTime: number,
276	    providedId?: string,
277	  ): string | undefined => {
278	    const state = get();
279	    const clip = state.clips[id];
280	    if (!clip) return undefined;
281	    if (!isAudioClip(clip)) return undefined;
282	
283	    const clipEnd = clip.startTime + clip.duration;
284	    if (atTime <= clip.startTime || atTime >= clipEnd) return undefined;
285	
286	    const leftDuration = atTime - clip.startTime;
287	    const rightDuration = clip.duration - leftDuration;
288	    const rightSourceOffset = clip.sourceOffset + leftDuration;
289	
290	    const newId = providedId ?? nextClipId();
291	
292	    const leftClip: ClipModel = { ...clip, duration: leftDuration };
293	    const rightClip: ClipModel = {
294	      ...clip,
295	      id: newId,
296	      startTime: atTime,
297	      sourceOffset: rightSourceOffset,
298	      duration: rightDuration,
299	    };
300	
301	    set((s) => {
302	      const nextClips = { ...s.clips, [id]: leftClip, [newId]: rightClip };
303	      const tracks = s.tracks.map((t) =>
304	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
305	      );
306	      return { clips: nextClips, tracks };
307	    });
308	
309	    return newId;
310	  },
311	
312	  trimClip: (id: string, newStart?: number, newEnd?: number) => {
313	    set((state) => {
314	      const clip = state.clips[id];
315	      if (!clip) return state;
316	      if (!isAudioClip(clip)) return state;
317	
318	      let { startTime, sourceOffset, duration } = clip;
319	      const clipEnd = startTime + duration;
320	
321	      if (newStart !== undefined) {
322	        const delta = newStart - startTime;
323	        startTime = newStart;
324	        sourceOffset = sourceOffset + delta;
325	        duration = clipEnd - newStart;
326	      }
327	
328	      if (newEnd !== undefined) {
329	        duration = newEnd - startTime;
330	      }
331	
332	      // Guard against invalid state
333	      if (duration <= 0 || sourceOffset < 0) return state;
334	
335	      return {
336	        clips: {
337	          ...state.clips,
338	          [id]: { ...clip, startTime, sourceOffset, duration },
339	        },
340	      };
341	    });
342	  },
343	
344	  duplicateClip: (id: string, providedId?: string): string | undefined => {
345	    const state = get();
346	    const clip = state.clips[id];
347	    if (!clip) return undefined;
348	
349	    const newId = providedId ?? nextClipId();
350	    const duplicate: ClipModel = {
351	      ...clip,
352	      id: newId,
353	      startTime: clip.startTime + clip.duration,
354	    };
355	
356	    set((s) => {
357	      const nextClips = { ...s.clips, [newId]: duplicate };
358	      const tracks = s.tracks.map((t) =>
359	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
360	      );
361	      return { clips: nextClips, tracks };
362	    });
363	
364	    return newId;
365	  },
366	
367	  // MIDI clip actions
368	  addMidiClip: (clip: MidiClipModel) => {
369	    set((state) => {
370	      const nextClips = { ...state.clips, [clip.id]: clip };
371	      const tracks = state.tracks.map((t) =>
372	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, clip.id] } : t,
373	      );
374	      return { clips: nextClips, tracks };
375	    });
376	  },
377	
378	  removeMidiClip: (id: string) => {
379	    set((state) => {
380	      const clip = state.clips[id];
381	      if (!clip) return state;
382	      const nextClips = Object.fromEntries(
383	        Object.entries(state.clips).filter(([k]) => k !== id),
384	      );
385	      const tracks = state.tracks.map((t) =>
386	        t.id === clip.trackId
387	          ? { ...t, clipIds: t.clipIds.filter((cid) => cid !== id) }
388	          : t,
389	      );
390	      return { clips: nextClips, tracks };
391	    });
392	  },
393	
394	  addNoteEvent: (clipId: string, note: MIDINoteEvent) => {
395	    set((state) => {
396	      const clip = state.clips[clipId];
397	      if (!clip || !isMidiClip(clip)) return state;
398	      const clamped: MIDINoteEvent = {
399	        ...note,
400	        pitch: Math.max(0, Math.min(127, Math.round(note.pitch))),
401	        velocity: Math.max(0, Math.min(127, Math.round(note.velocity))),
402	        startTime: Math.max(0, note.startTime),
403	        duration: Math.max(0.01, note.duration),
404	      };
405	      const updated: MidiClipModel = {
406	        ...clip,
407	        noteEvents: [...clip.noteEvents, clamped],
408	      };
409	      return { clips: { ...state.clips, [clipId]: updated } };
410	    });
411	  },
412	
413	  removeNoteEvent: (clipId: string, noteId: string) => {
414	    set((state) => {
415	      const clip = state.clips[clipId];
416	      if (!clip || !isMidiClip(clip)) return state;
417	      const updated: MidiClipModel = {
418	        ...clip,
419	        noteEvents: clip.noteEvents.filter((n) => n.id !== noteId),
420	      };
421	      return { clips: { ...state.clips, [clipId]: updated } };
422	    });
423	  },
424	
425	  moveNoteEvent: (
426	    clipId: string,
427	    noteId: string,
428	    newStartTime: number,
429	    newPitch: number,
430	  ) => {
431	    set((state) => {
432	      const clip = state.clips[clipId];
433	      if (!clip || !isMidiClip(clip)) return state;
434	      const clampedPitch = Math.max(0, Math.min(127, Math.round(newPitch)));
435	      const clampedStartTime = Math.max(0, newStartTime);
436	      const updated: MidiClipModel = {
437	        ...clip,
438	        noteEvents: clip.noteEvents.map((n) =>
439	          n.id === noteId
440	            ? { ...n, startTime: clampedStartTime, pitch: clampedPitch }
441	            : n,
442	        ),
443	      };
444	      return { clips: { ...state.clips, [clipId]: updated } };
445	    });
446	  },
447	
448	  resizeNoteEvent: (clipId: string, noteId: string, newDuration: number) => {
449	    set((state) => {
450	      const clip = state.clips[clipId];
451	      if (!clip || !isMidiClip(clip)) return state;
452	      const clampedDuration = Math.max(0.01, newDuration);
453	      const updated: MidiClipModel = {
454	        ...clip,
455	        noteEvents: clip.noteEvents.map((n) =>
456	          n.id === noteId ? { ...n, duration: clampedDuration } : n,
457	        ),
458	      };
459	      return { clips: { ...state.clips, [clipId]: updated } };
460	    });
461	  },
462	
463	  updateNoteVelocity: (clipId: string, noteId: string, velocity: number) => {
464	    set((state) => {
465	      const clip = state.clips[clipId];
466	      if (!clip || !isMidiClip(clip)) return state;
467	      const clampedVelocity = Math.max(0, Math.min(127, Math.round(velocity)));
468	      const updated: MidiClipModel = {
469	        ...clip,
470	        noteEvents: clip.noteEvents.map((n) =>
471	          n.id === noteId ? { ...n, velocity: clampedVelocity } : n,
472	        ),
473	      };
474	      return { clips: { ...state.clips, [clipId]: updated } };
475	    });
476	  },
477	
478	  // Selection
479	  setSelectedTrackIds: (ids: readonly string[]) => {
480	    set({ selectedTrackIds: ids });
481	  },
482	  setSelectedClipIds: (ids: readonly string[]) => {
483	    set({ selectedClipIds: ids });
484	  },
485	  setSelectedNoteIds: (ids: readonly string[]) => {
486	    set({ selectedNoteIds: ids });
487	  },
488	
489	  // Query
490	  queryClipsAtTime: (time: number): readonly ClipModel[] => {
491	    const state = get();
492	    const hasSolo = state.tracks.some((t) => t.solo);
493	    const activeTracks = new Set(
494	      state.tracks
495	        .filter((t) => {
496	          if (t.muted) return false;
497	          if (hasSolo && !t.solo && !t.soloIsolate) return false;
498	          return true;
499	        })
500	        .map((t) => t.id),
501	    );
502	
503	    return Object.values(state.clips).filter((clip) => {
504	      if (!activeTracks.has(clip.trackId)) return false;
505	      const clipEnd = clip.startTime + clip.duration;
506	      return time >= clip.startTime && time < clipEnd;
507	    });
508	  },
509	}));
