1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { useDawStore } from "@state/store";
3	import { useAutomationStore } from "@state/automation";
4	import { isAudioClip, type AudioClipModel } from "@state/track/types";
5	import { AddClipCommand } from "@state/track/track-commands";
6	import { sharedUndoManager } from "@state/undo";
7	import { useMediaPool } from "@audio/media-pool/use-media-pool";
8	import { useAudioEngine } from "@audio/use-audio-engine";
9	import { useTransport } from "@audio/use-transport";
10	import { useTransportCursor } from "@ui/hooks/useTransportCursor";
11	import {
12	  renderArrangement,
13	  type ArrangementViewState,
14	} from "./arrangement-renderer";
15	import { useArrangementInteractions } from "./use-arrangement-interactions";
16	import { xToSeconds, snapToGrid, type GridSnap } from "./hit-test";
17	import { RULER_HEIGHT } from "./constants";
18	import styles from "./ArrangementPanel.module.css";
19	
20	const DEFAULT_VIEW: ArrangementViewState = {
21	  scrollX: 0,
22	  scrollY: 0,
23	  pixelsPerSecond: 100,
24	  trackHeight: 64,
25	  headerWidth: 160,
26	};
27	
28	const MIN_PPS = 10;
29	const MAX_PPS = 500;
30	const ZOOM_FACTOR = 1.1;
31	
32	type ArrangementPanelProps = {
33	  onOpenPianoRoll?: (clipId: string) => void;
34	};
35	
36	export function ArrangementPanel({
37	  onOpenPianoRoll,
38	}: ArrangementPanelProps): React.JSX.Element {
39	  const canvasRef = useRef<HTMLCanvasElement>(null);
40	  const rafRef = useRef(0);
41	  const [view, setView] = useState(DEFAULT_VIEW);
42	  const [gridSnap] = useState<GridSnap>("1/4");
43	  const interactions = useArrangementInteractions(
44	    view,
45	    gridSnap,
46	    onOpenPianoRoll,
47	  );
48	  const bpmForDrop = useDawStore((s) => s.bpm);
49	  const transport = useTransport();
50	  const sabCursorRef = useTransportCursor(transport.getTransportSAB());
51	
52	  const handleDragOver = useCallback(
53	    (e: React.DragEvent<HTMLCanvasElement>): void => {
54	      if (!e.dataTransfer.types.includes("application/x-media-pool-source"))
55	        return;
56	
57	      const rect = e.currentTarget.getBoundingClientRect();
58	      const y = e.clientY - rect.top;
59	      const trackIndex = Math.floor(
60	        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
61	      );
62	      const state = useDawStore.getState();
63	      const track = trackIndex >= 0 ? state.tracks[trackIndex] : undefined;
64	      if (track !== undefined && track.type === "audio") {
65	        e.preventDefault();
66	        e.dataTransfer.dropEffect = "copy";
67	      }
68	    },
69	    [view],
70	  );
71	
72	  const handleDrop = useCallback(
73	    (e: React.DragEvent<HTMLCanvasElement>): void => {
74	      const raw = e.dataTransfer.getData("application/x-media-pool-source");
75	      if (!raw) return;
76	      e.preventDefault();
77	
78	      let parsed: unknown;
79	      try {
80	        parsed = JSON.parse(raw);
81	      } catch {
82	        return;
83	      }
84	      const data = parsed as Record<string, unknown>;
85	      if (
86	        typeof data.sourceId !== "string" ||
87	        typeof data.name !== "string" ||
88	        typeof data.durationSeconds !== "number"
89	      )
90	        return;
91	
92	      const rect = e.currentTarget.getBoundingClientRect();
93	      const x = e.clientX - rect.left;
94	      const y = e.clientY - rect.top;
95	
96	      const state = useDawStore.getState();
97	      const trackIndex = Math.floor(
98	        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
99	      );
100	      if (trackIndex < 0) return;
101	      const track = state.tracks[trackIndex];
102	      if (track === undefined || track.type !== "audio") return;
103	
104	      const dropTime = snapToGrid(
105	        Math.max(0, xToSeconds(x, view)),
106	        bpmForDrop,
107	        gridSnap,
108	      );
109	
110	      const clip: AudioClipModel = {
111	        type: "audio",
112	        id: "clip-" + crypto.randomUUID(),
113	        trackId: track.id,
114	        sourceId: data.sourceId,
115	        startTime: dropTime,
