/**
 * Pointer interaction handlers for the arrangement canvas.
 * Manages drag operations for clip move, trim, split, and selection.
 * Pushes undo commands on drag completion.
 */
import { useCallback, useRef, useState } from "react";
import { useDawStore } from "@state/store";
import type { ClipModel, MidiClipModel } from "@state/track/types";
import { isAudioClip, isMidiClip } from "@state/track/types";
import type { UndoCommand } from "@state/undo";
import { sharedUndoManager } from "@state/undo";
import {
  AddClipCommand,
  RemoveClipCommand,
  RemoveTrackCommand,
  SplitClipCommand,
} from "@state/track/track-commands";
import type { ArrangementViewState } from "./arrangement-renderer";
import { hitTest, xToSeconds, snapToGrid, type GridSnap } from "./hit-test";
import { RULER_HEIGHT } from "./constants";

type DragState =
  | { kind: "idle" }
  | {
      kind: "move-clip";
      clipId: string;
      originTrackId: string;
      startX: number;
      startTime: number;
      beforeClip: ClipModel;
    }
  | {
      kind: "trim-left";
      clipId: string;
      startX: number;
      originalStart: number;
      originalSourceOffset: number;
      originalDuration: number;
      beforeClip: ClipModel;
    }
  | {
      kind: "trim-right";
      clipId: string;
      startX: number;
      originalEnd: number;
      originalStart: number;
      beforeClip: ClipModel;
    }
  | {
      kind: "rubber-band";
      startX: number;
      startY: number;
    };

export type ArrangementInteractions = {
  onPointerDown: (e: React.PointerEvent<HTMLCanvasElement>) => void;
  onPointerMove: (e: React.PointerEvent<HTMLCanvasElement>) => void;
  onPointerUp: (e: React.PointerEvent<HTMLCanvasElement>) => void;
  onDoubleClick: (e: React.MouseEvent<HTMLCanvasElement>) => void;
  onKeyDown: (e: React.KeyboardEvent<HTMLCanvasElement>) => void;
  cursor: string;
};

export function useArrangementInteractions(
  view: ArrangementViewState,
  gridSnap: GridSnap,
  onOpenPianoRoll?: (clipId: string) => void,
): ArrangementInteractions {
  const dragRef = useRef<DragState>({ kind: "idle" });
  const [cursor, setCursor] = useState("default");

  const getCanvasPos = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>): { x: number; y: number } => {
      const rect = e.currentTarget.getBoundingClientRect();
      return { x: e.clientX - rect.left, y: e.clientY - rect.top };
    },
    [],
  );

  const onPointerDown = useCallback(
    (e: React.PointerEvent<HTMLCanvasElement>): void => {
      const { x, y } = getCanvasPos(e);
      const state = useDawStore.getState();
      const hit = hitTest(x, y, view, state.tracks, state.clips);

      switch (hit.kind) {
        case "clip-body": {
          const clip = state.clips[hit.clipId];
          if (clip === undefined) break;

          if (e.shiftKey) {
            const current = [...state.selectedClipIds];
            const idx = current.indexOf(hit.clipId);
            if (idx >= 0) {
              current.splice(idx, 1);
            } else {
              current.push(hit.clipId);
            }
            state.setSelectedClipIds(current);
          } else if (!state.selectedClipIds.includes(hit.clipId)) {
            state.setSelectedClipIds([hit.clipId]);
          }

          e.currentTarget.setPointerCapture(e.pointerId);
          dragRef.current = {
            kind: "move-clip",
            clipId: hit.clipId,
            originTrackId: clip.trackId,
            startX: x,
            startTime: clip.startTime,
            beforeClip: { ...clip },
          };
          break;
        }
        case "clip-left-edge": {
          const clip = state.clips[hit.clipId];
          if (clip === undefined) break;
          state.setSelectedClipIds([hit.clipId]);
          e.currentTarget.setPointerCapture(e.pointerId);
          dragRef.current = {
            kind: "trim-left",
            clipId: hit.clipId,
            startX: x,
            originalStart: clip.startTime,
            originalSourceOffset: isAudioClip(clip) ? clip.sourceOffset : 0,
            originalDuration: clip.duration,
            beforeClip: { ...clip },
          };
          break;
        }
        case "clip-right-edge": {
          const clip = state.clips[hit.clipId];
          if (clip === undefined) break;
          state.setSelectedClipIds([hit.clipId]);
          e.currentTarget.setPointerCapture(e.pointerId);
          dragRef.current = {
            kind: "trim-right",
            clipId: hit.clipId,
            startX: x,
            originalEnd: clip.startTime + clip.duration,
            originalStart: clip.startTime,
            beforeClip: { ...clip },
          };
          break;
        }
        case "ruler": {
          state.setCursor(Math.max(0, hit.timeSeconds));
          break;
        }
        case "empty-lane": {
          if (!e.shiftKey) {
            state.setSelectedClipIds([]);
          }
          e.currentTarget.setPointerCapture(e.pointerId);
          dragRef.current = { kind: "rubber-band", startX: x, startY: y };
          break;
        }
        case "track-header": {
          if (e.shiftKey) {
            const current = [...state.selectedTrackIds];
            const idx = current.indexOf(hit.trackId);
            if (idx >= 0) {
              current.splice(idx, 1);
            } else {
              current.push(hit.trackId);
            }
            state.setSelectedTrackIds(current);
          } else {
            state.setSelectedTrackIds([hit.trackId]);
          }
          break;
        }
        case "none":
          break;
      }
    },
    [view, getCanvasPos],
  );

  const onPointerMove = useCallback(
    (e: React.PointerEvent<HTMLCanvasElement>): void => {
      const { x, y } = getCanvasPos(e);
      const drag = dragRef.current;
      const state = useDawStore.getState();

      if (drag.kind === "idle") {
        const hit = hitTest(x, y, view, state.tracks, state.clips);
        switch (hit.kind) {
          case "clip-left-edge":
          case "clip-right-edge":
            setCursor("ew-resize");
            break;
          case "clip-body":
            setCursor("grab");
            break;
          default:
            setCursor("default");
            break;
        }
        return;
      }

      switch (drag.kind) {
        case "move-clip": {
          setCursor("grabbing");
          const deltaPx = x - drag.startX;
          const deltaSec = deltaPx / view.pixelsPerSecond;
          const newTime = snapToGrid(
            Math.max(0, drag.startTime + deltaSec),
            state.bpm,
            gridSnap,
          );

          const trackIndex = Math.floor(
            (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
          );
          const targetTrack = state.tracks[trackIndex];
          const targetTrackId =
            targetTrack !== undefined ? targetTrack.id : drag.originTrackId;

          state.moveClip(drag.clipId, newTime, targetTrackId);
          break;
        }
        case "trim-left": {
          setCursor("ew-resize");
          const deltaPx = x - drag.startX;
          const deltaSec = deltaPx / view.pixelsPerSecond;
          const newStart = snapToGrid(
            Math.max(0, drag.originalStart + deltaSec),
            state.bpm,
            gridSnap,
          );
          const maxStart = drag.originalStart + drag.originalDuration - 0.01;
          const clampedStart = Math.min(newStart, maxStart);
          state.trimClip(drag.clipId, clampedStart, undefined);
          break;
        }
        case "trim-right": {
          setCursor("ew-resize");
          const deltaPx = x - drag.startX;
          const deltaSec = deltaPx / view.pixelsPerSecond;
          const rawEnd = snapToGrid(
            Math.max(0.01, drag.originalEnd + deltaSec),
            state.bpm,
            gridSnap,
          );
          // Clamp so the end never crosses the clip's start
          const newEnd = Math.max(drag.originalStart + 0.01, rawEnd);
          state.trimClip(drag.clipId, undefined, newEnd);
          break;
        }
        case "rubber-band": {
          const left = Math.min(drag.startX, x);
          const right = Math.max(drag.startX, x);
          const top = Math.min(drag.startY, y);
          const bottom = Math.max(drag.startY, y);

          const selected: string[] = [];
          for (let ti = 0; ti < state.tracks.length; ti++) {
            const track = state.tracks[ti];
            if (track === undefined) continue;
            const trackTop =
              RULER_HEIGHT + ti * view.trackHeight - view.scrollY;
            const trackBottom = trackTop + view.trackHeight;
            if (trackBottom < top || trackTop > bottom) continue;

            for (const clipId of track.clipIds) {
              const clip = state.clips[clipId];
              if (clip === undefined) continue;
              const clipLeft =
                view.headerWidth +
                (clip.startTime - view.scrollX) * view.pixelsPerSecond;
              const clipRight = clipLeft + clip.duration * view.pixelsPerSecond;
              if (clipRight >= left && clipLeft <= right) {
                selected.push(clip.id);
              }
            }
          }
          state.setSelectedClipIds(selected);
          break;
        }
      }
    },
    [view, gridSnap, getCanvasPos],
  );

  const onPointerUp = useCallback(
    (e: React.PointerEvent<HTMLCanvasElement>): void => {
      const drag = dragRef.current;

      // Push undo commands for clip-mutating drags
      if (
        drag.kind === "move-clip" ||
        drag.kind === "trim-left" ||
        drag.kind === "trim-right"
      ) {
        const afterClip = useDawStore.getState().clips[drag.clipId];
        const before = drag.beforeClip;

        if (
          afterClip !== undefined &&
          (before.startTime !== afterClip.startTime ||
            before.trackId !== afterClip.trackId ||
            before.duration !== afterClip.duration ||
            (isAudioClip(before) &&
              isAudioClip(afterClip) &&
              before.sourceOffset !== afterClip.sourceOffset))
        ) {
          const clipId = drag.clipId;
          const cmd: UndoCommand =
            drag.kind === "move-clip"
              ? {
                  type: "move-clip-drag",
                  execute() {
                    useDawStore
                      .getState()
                      .moveClip(clipId, afterClip.startTime, afterClip.trackId);
                  },
                  undo() {
                    useDawStore
                      .getState()
                      .moveClip(clipId, before.startTime, before.trackId);
                  },
                  serialize() {
                    return { clipId, before, after: afterClip };
                  },
                }
              : {
                  type: "trim-clip-drag",
                  execute() {
                    useDawStore.setState((s) => ({
                      clips: { ...s.clips, [clipId]: afterClip },
                    }));
                  },
                  undo() {
                    useDawStore.setState((s) => ({
                      clips: { ...s.clips, [clipId]: before },
                    }));
                  },
                  serialize() {
                    return { clipId, before, after: afterClip };
                  },
                };
          sharedUndoManager.push(cmd);
        }
      }

      if (drag.kind !== "idle") {
        e.currentTarget.releasePointerCapture(e.pointerId);
      }
      dragRef.current = { kind: "idle" };
      setCursor("default");
    },
    [],
  );

  const onDoubleClick = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>): void => {
      const { x, y } = getCanvasPos(e);
      const state = useDawStore.getState();
      const hit = hitTest(x, y, view, state.tracks, state.clips);

      if (hit.kind === "clip-body") {
        const clip = state.clips[hit.clipId];
        if (clip !== undefined && isMidiClip(clip)) {
          onOpenPianoRoll?.(hit.clipId);
          return;
        }
        const timeSec = xToSeconds(x, view);
        const cmd = new SplitClipCommand(hit.clipId, timeSec);
        cmd.execute();
        sharedUndoManager.push(cmd);
        return;
      }

      // Double-click on empty lane of instrument/drum track creates a MIDI clip
      if (hit.kind === "empty-lane") {
        const track = state.tracks.find((t) => t.id === hit.trackId);
        if (
          track !== undefined &&
          (track.type === "instrument" || track.type === "drum")
        ) {
          const timeSec = snapToGrid(
            Math.max(0, xToSeconds(x, view)),
            state.bpm,
            gridSnap,
          );
          const barsInSeconds = (60 / state.bpm) * 4; // 1 bar = 4 beats
          const clip: MidiClipModel = {
            type: "midi",
            id: "clip-" + crypto.randomUUID(),
            trackId: track.id,
            startTime: timeSec,
            duration: barsInSeconds,
            noteEvents: [],
            name: "MIDI Clip",
          };
          const cmd = new AddClipCommand(clip);
          cmd.execute();
          sharedUndoManager.push(cmd);
        }
      }
    },
    [view, gridSnap, getCanvasPos, onOpenPianoRoll],
  );

  return {
    onPointerDown,
    onPointerMove,
    onPointerUp,
    onDoubleClick,
    cursor,
  };
}

import { useCallback, useEffect, useRef, useState } from "react";
import { useDawStore } from "@state/store";
import { useAutomationStore } from "@state/automation";
import { isAudioClip, type AudioClipModel } from "@state/track/types";
import { AddClipCommand } from "@state/track/track-commands";
import { sharedUndoManager } from "@state/undo";
import { useMediaPool } from "@audio/media-pool/use-media-pool";
import { useAudioEngine } from "@audio/use-audio-engine";
import { useTransport } from "@audio/use-transport";
import { useTransportCursor } from "@ui/hooks/useTransportCursor";
import {
  renderArrangement,
  type ArrangementViewState,
} from "./arrangement-renderer";
import { useArrangementInteractions } from "./use-arrangement-interactions";
import { xToSeconds, snapToGrid, type GridSnap } from "./hit-test";
import { RULER_HEIGHT } from "./constants";
import styles from "./ArrangementPanel.module.css";

const DEFAULT_VIEW: ArrangementViewState = {
  scrollX: 0,
  scrollY: 0,
  pixelsPerSecond: 100,
  trackHeight: 64,
  headerWidth: 160,
};

const MIN_PPS = 10;
const MAX_PPS = 500;
const ZOOM_FACTOR = 1.1;

type ArrangementPanelProps = {
  onOpenPianoRoll?: (clipId: string) => void;
};

export function ArrangementPanel({
  onOpenPianoRoll,
}: ArrangementPanelProps): React.JSX.Element {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef(0);
  const [view, setView] = useState(DEFAULT_VIEW);
  const [gridSnap] = useState<GridSnap>("1/4");
  const interactions = useArrangementInteractions(
    view,
    gridSnap,
    onOpenPianoRoll,
  );
  const bpmForDrop = useDawStore((s) => s.bpm);
  const transport = useTransport();
  const sabCursorRef = useTransportCursor(transport.getTransportSAB());

  const handleDragOver = useCallback(
    (e: React.DragEvent<HTMLCanvasElement>): void => {
      if (!e.dataTransfer.types.includes("application/x-media-pool-source"))
        return;

      const rect = e.currentTarget.getBoundingClientRect();
      const y = e.clientY - rect.top;
      const trackIndex = Math.floor(
        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
      );
      const state = useDawStore.getState();
      const track = trackIndex >= 0 ? state.tracks[trackIndex] : undefined;
      if (track !== undefined && track.type === "audio") {
        e.preventDefault();
        e.dataTransfer.dropEffect = "copy";
      }
    },
    [view],
  );

  const handleDrop = useCallback(
    (e: React.DragEvent<HTMLCanvasElement>): void => {
      const raw = e.dataTransfer.getData("application/x-media-pool-source");
      if (!raw) return;
      e.preventDefault();

      let parsed: unknown;
      try {
        parsed = JSON.parse(raw);
      } catch {
        return;
      }
      const data = parsed as Record<string, unknown>;
      if (
        typeof data.sourceId !== "string" ||
        typeof data.name !== "string" ||
        typeof data.durationSeconds !== "number"
      )
        return;

      const rect = e.currentTarget.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      const state = useDawStore.getState();
      const trackIndex = Math.floor(
        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
      );
      if (trackIndex < 0) return;
      const track = state.tracks[trackIndex];
      if (track === undefined || track.type !== "audio") return;

      const dropTime = snapToGrid(
        Math.max(0, xToSeconds(x, view)),
        bpmForDrop,
        gridSnap,
      );

      const clip: AudioClipModel = {
        type: "audio",
        id: "clip-" + crypto.randomUUID(),
        trackId: track.id,
        sourceId: data.sourceId,
        startTime: dropTime,
        sourceOffset: 0,
        duration: data.durationSeconds,
        gain: 1,
        fadeIn: 0,
        fadeOut: 0,
        name: data.name,
      };

      const cmd = new AddClipCommand(clip);
      cmd.execute();
      sharedUndoManager.push(cmd);
    },
    [view, gridSnap, bpmForDrop],
  );

  const tracks = useDawStore((s) => s.tracks);
  const clips = useDawStore((s) => s.clips);
  const selectedClipIds = useDawStore((s) => s.selectedClipIds);
  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
  const bpm = useDawStore((s) => s.bpm);
  const transportState = useDawStore((s) => s.transportState);
  const automationLanes = useAutomationStore((s) => s.lanes);
  const pool = useMediaPool();
  const engine = useAudioEngine();

  // Fetch and slice waveform peaks per audio clip
  const SAMPLES_PER_PEAK = 256;
  const [clipPeaks, setClipPeaks] = useState<
    Record<string, { peaks: Float32Array; length: number }>
  >({});

  useEffect(() => {
    let cancelled = false;
    const sampleRate = engine.ctx.sampleRate;

    async function fetchPeaks(): Promise<void> {
      const result: Record<string, { peaks: Float32Array; length: number }> =
        {};
      for (const clip of Object.values(clips)) {
        if (!isAudioClip(clip)) continue;
        const wp = await pool.getPeaks(clip.sourceId, SAMPLES_PER_PEAK);
        if (cancelled) return;
        if (!wp || wp.length === 0) continue;

        // Slice peaks to match clip's sourceOffset and duration
        const startPeak = Math.floor(
          (clip.sourceOffset * sampleRate) / wp.samplesPerPeak,
        );
        const peakCount = Math.ceil(
          (clip.duration * sampleRate) / wp.samplesPerPeak,
        );
        const endPeak = Math.min(startPeak + peakCount, wp.length);
        const sliceLen = Math.max(0, endPeak - startPeak);

        result[clip.id] = {
          peaks: wp.peaks.slice(startPeak * 2, endPeak * 2),
          length: sliceLen,
        };
      }
      if (!cancelled) setClipPeaks(result);
    }

    void fetchPeaks();
    return () => {
      cancelled = true;
    };
  }, [clips, pool, engine.ctx.sampleRate]);

  // Render the arrangement canvas
  const render = useCallback((): void => {
    const canvas = canvasRef.current;
    if (canvas === null) return;
    const ctx = canvas.getContext("2d");
    if (ctx === null) return;
    const rect = canvas.getBoundingClientRect();
    renderArrangement({
      ctx,
      width: rect.width,
      height: rect.height,
      view,
      tracks,
      clips,
      selectedClipIds,
      cursorSeconds,
      bpm,
      automationLanes,
      clipPeaks,
    });
  }, [
    view,
    tracks,
    clips,
    selectedClipIds,
    cursorSeconds,
    bpm,
    automationLanes,
    clipPeaks,
  ]);

  // Schedule re-render when state changes or during playback.
  // During playback, read cursor from SAB (updated by audio thread) to keep
  // the playback cursor moving smoothly.
  useEffect(() => {
    if (transportState !== "playing") {
      render();
      return;
    }

    const tick = (): void => {
      const canvas = canvasRef.current;
      if (canvas !== null) {
        const ctx = canvas.getContext("2d");
        if (ctx !== null) {
          const rect = canvas.getBoundingClientRect();
          renderArrangement({
            ctx,
            width: rect.width,
            height: rect.height,
            view,
            tracks,
            clips,
            selectedClipIds,
            cursorSeconds: sabCursorRef.current,
            bpm,
            automationLanes,
            clipPeaks,
          });
        }
      }
      rafRef.current = requestAnimationFrame(tick);
    };

    rafRef.current = requestAnimationFrame(tick);
    return (): void => {
      cancelAnimationFrame(rafRef.current);
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps -- RAF loop reads SAB directly; deps trigger effect restart on state changes
  }, [render, transportState]);

  // Handle canvas sizing with ResizeObserver
  useEffect(() => {
    const canvas = canvasRef.current;
    if (canvas === null) return;
    const parent = canvas.parentElement;
    if (parent === null) return;

    const resizeCanvas = (): void => {
      const dpr = window.devicePixelRatio;
      const rect = parent.getBoundingClientRect();
      canvas.width = rect.width * dpr;
      canvas.height = rect.height * dpr;
      canvas.style.width = `${String(rect.width)}px`;
      canvas.style.height = `${String(rect.height)}px`;

      const ctx = canvas.getContext("2d");
      if (ctx !== null) {
        ctx.scale(dpr, dpr);
      }
    };

    if (typeof ResizeObserver === "undefined") return;

    const observer = new ResizeObserver(resizeCanvas);
    observer.observe(parent);
    resizeCanvas();

    return (): void => {
      observer.disconnect();
    };
  }, []);

  // Wheel: ctrl+wheel for zoom, plain wheel for scroll
  const handleWheel = useCallback(
    (e: React.WheelEvent<HTMLCanvasElement>): void => {
      e.preventDefault();

      if (e.ctrlKey || e.metaKey) {
        // Zoom
        const factor = e.deltaY < 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
        setView((prev) => ({
          ...prev,
          pixelsPerSecond: Math.min(
            MAX_PPS,
            Math.max(MIN_PPS, prev.pixelsPerSecond * factor),
          ),
        }));
      } else if (e.shiftKey) {
        // Horizontal scroll
        setView((prev) => ({
          ...prev,
          scrollX: Math.max(0, prev.scrollX + e.deltaY / prev.pixelsPerSecond),
        }));
      } else {
        // Vertical scroll
        setView((prev) => ({
          ...prev,
          scrollX: Math.max(0, prev.scrollX + e.deltaX / prev.pixelsPerSecond),
          scrollY: Math.max(0, prev.scrollY + e.deltaY),
        }));
      }
    },
    [],
  );

  return (
    <section data-testid="arrangement-panel" className={styles["container"]}>
      <span id="arrangement-keys" hidden>
        Scroll: mouse wheel. Horizontal scroll: Shift + wheel. Zoom: Ctrl/Cmd +
        wheel. Double-click to create clip. Click to select. Drag to move clips.
      </span>
      <canvas
        ref={canvasRef}
        role="application"
        aria-label="Arrangement timeline"
        aria-describedby="arrangement-keys"
        className={styles["canvas"]}
        style={{ cursor: interactions.cursor }}
        onWheel={handleWheel}
        onPointerDown={interactions.onPointerDown}
        onPointerMove={interactions.onPointerMove}
        onPointerUp={interactions.onPointerUp}
        onDoubleClick={interactions.onDoubleClick}
        onDragOver={handleDragOver}
        onDrop={handleDrop}
      />
    </section>
  );
}

