1	/**
2	 * Virtual piano keyboard for mouse-triggered notes.
3	 * 2-octave range (C3-B4) with black/white keys.
4	 * Neo-brutalist styling with thick borders.
5	 */
6	
7	import { useCallback, useRef } from "react";
8	import { tokens } from "@ui/tokens/tokens";
9	
10	type VirtualKeyboardProps = {
11	  onNoteOn: (note: number, velocity: number) => void;
12	  onNoteOff: (note: number) => void;
13	};
14	
15	const OCTAVE_START = 48; // C3
16	const NUM_OCTAVES = 2;
17	
18	/** White key indices within an octave (C D E F G A B) */
19	const WHITE_KEY_OFFSETS = [0, 2, 4, 5, 7, 9, 11];
20	/** Black key indices within an octave */
21	const BLACK_KEY_OFFSETS = [1, 3, 6, 8, 10];
22	/** Black key positions relative to white keys (0-indexed from C) */
23	const BLACK_KEY_POSITIONS = [0.7, 1.7, 3.7, 4.7, 5.7];
24	
25	const WHITE_KEY_WIDTH = 28;
26	const WHITE_KEY_HEIGHT = 80;
27	const BLACK_KEY_WIDTH = 18;
28	const BLACK_KEY_HEIGHT = 50;
29	
30	const WHITE_KEY_BORDER =
31	  String(tokens.border.width) + "px solid " + tokens.color.black;
32	const BLACK_KEY_BORDER =
33	  String(tokens.border.width) + "px solid " + tokens.color.gray700;
34	
35	export function VirtualKeyboard({
36	  onNoteOn,
37	  onNoteOff,
38	}: VirtualKeyboardProps): React.JSX.Element {
39	  const activeNotes = useRef(new Set<number>());
40	
41	  const handleMouseDown = useCallback(
42	    (note: number) => {
43	      // Release first if already active (prevents stuck notes on rapid clicks)
44	      if (activeNotes.current.has(note)) {
45	        onNoteOff(note);
46	      }
47	      activeNotes.current.add(note);
48	      onNoteOn(note, 100);
49	    },
50	    [onNoteOn, onNoteOff],
51	  );
52	
53	  const handleMouseUp = useCallback(
54	    (note: number) => {
55	      if (activeNotes.current.has(note)) {
56	        activeNotes.current.delete(note);
57	        onNoteOff(note);
58	      }
59	    },
60	    [onNoteOff],
61	  );
62	
63	  const handleMouseLeave = useCallback(
64	    (note: number) => {
65	      if (activeNotes.current.has(note)) {
66	        activeNotes.current.delete(note);
67	        onNoteOff(note);
68	      }
69	    },
70	    [onNoteOff],
71	  );
72	
73	  const whiteKeys: React.JSX.Element[] = [];
74	  const blackKeys: React.JSX.Element[] = [];
75	
76	  let whiteIndex = 0;
77	
78	  for (let octave = 0; octave < NUM_OCTAVES; octave++) {
79	    for (const offset of WHITE_KEY_OFFSETS) {
80	      const note = OCTAVE_START + octave * 12 + offset;
81	      const x = whiteIndex * WHITE_KEY_WIDTH;
82	      whiteKeys.push(
83	        <div
84	          key={"w-" + String(note)}
85	          data-testid={"key-" + String(note)}
86	          onMouseDown={() => {
87	            handleMouseDown(note);
88	          }}
89	          onMouseUp={() => {
90	            handleMouseUp(note);
91	          }}
92	          onMouseLeave={() => {
93	            handleMouseLeave(note);
94	          }}
95	          style={{
96	            position: "absolute",
97	            left: x,
98	            top: 0,
99	            width: WHITE_KEY_WIDTH,
100	            height: WHITE_KEY_HEIGHT,
101	            backgroundColor: tokens.color.white,
102	            border: WHITE_KEY_BORDER,
103	            cursor: "pointer",
104	            userSelect: "none",
105	            zIndex: 1,
106	          }}
107	        />,
108	      );
109	      whiteIndex++;
110	    }
111	
112	    for (let bi = 0; bi < BLACK_KEY_OFFSETS.length; bi++) {
113	      const offset = BLACK_KEY_OFFSETS[bi] ?? 0;
114	      const pos = BLACK_KEY_POSITIONS[bi] ?? 0;
115	      const note = OCTAVE_START + octave * 12 + offset;
116	      const x =
117	        (octave * WHITE_KEY_OFFSETS.length + pos) * WHITE_KEY_WIDTH +
118	        (WHITE_KEY_WIDTH - BLACK_KEY_WIDTH) / 2;
119	
120	      blackKeys.push(
121	        <div
122	          key={"b-" + String(note)}
123	          data-testid={"key-" + String(note)}
124	          onMouseDown={() => {
125	            handleMouseDown(note);
126	          }}
127	          onMouseUp={() => {
128	            handleMouseUp(note);
129	          }}
130	          onMouseLeave={() => {
131	            handleMouseLeave(note);
132	          }}
133	          style={{
134	            position: "absolute",
135	            left: x,
136	            top: 0,
137	            width: BLACK_KEY_WIDTH,
138	            height: BLACK_KEY_HEIGHT,
139	            backgroundColor: tokens.color.black,
140	            border: BLACK_KEY_BORDER,
141	            cursor: "pointer",
142	            userSelect: "none",
143	            zIndex: 2,
144	          }}
145	        />,
146	      );
147	    }
148	  }
149	
150	  const totalWidth = whiteIndex * WHITE_KEY_WIDTH;
151	
152	  return (
153	    <div
154	      data-testid="virtual-keyboard"
155	      style={{
156	        position: "relative",
157	        width: totalWidth,
158	        height: WHITE_KEY_HEIGHT,
159	        flexShrink: 0,
160	      }}
161	    >
162	      {whiteKeys}
163	      {blackKeys}
164	    </div>
165	  );
166	}
167

