15	    fireEvent.pointerDown(screen.getByRole("button"));
16	    expect(onTrigger).toHaveBeenCalledOnce();
17	  });
18	
19	  it("has aria-pressed true when active", () => {
20	    render(<DrumPad label="HiHat" active onTrigger={vi.fn()} />);
21	    expect(screen.getByRole("button")).toHaveAttribute("aria-pressed", "true");
22	  });
23	
24	  it("has aria-pressed false when not active", () => {
25	    render(<DrumPad label="HiHat" onTrigger={vi.fn()} />);
26	    expect(screen.getByRole("button")).toHaveAttribute("aria-pressed", "false");
27	  });
28	
29	  it("shows label text", () => {
30	    render(<DrumPad label="Clap" onTrigger={vi.fn()} />);
31	    expect(screen.getByText("Clap")).toBeInTheDocument();
32	  });
